// Unit 8. Gezondheid & Gevoel
// Imperative, Comparatives & Body

export default {n:8,lang:"nl",srcLang:"en",track:"v2",title:"Gezondheid & Gevoel",sub:"Imperative, Comparatives & Body",icon:"🏥",level:"A2.1",color:"#7B5EE8",lessons:[
  {id:"v2u8l1",title:"Mijn Hoofd, Mijn Buik",icon:"🦶",xp:15,board:true,steps:[
        {type:"intro",title:"Mijn Hoofd, Mijn Buik",desc:"Before you can talk about health, you need the body. Dutch body part vocabulary is full of Germanic cognates. head/hoofd, hand/hand, foot/voet. This lesson teaches 12 essential body parts and the construction 'Ik heb pijn in mijn...' (I have pain in my...).",goals:["12 body parts with articles","'Ik heb pijn in mijn...' construction","'Ik heb hoofdpijn/buikpijn/rugpijn'","Compound pain words"]},
        {type:"teach",trg:"het hoofd",src:"the head",pos:"noun",gender:"n",phonetic:"hut hohft",note:"Het-word. Formal; informal = 'het hoofd' or just 'kop'.\n'Hoofdpijn' = headache (compound word).",example:"A: Ik heb pijn in mijn hoofd.\nB: Gaat het goed met je?\nA: Klopt!",exampleSrc:"A: I have pain in my head.\nB: Are you doing okay?\nA: Right!",funFact:"Germanic cousin of English 'head', German 'Haupt'."},
        {type:"teach",trg:"de buik",src:"the belly / stomach",pos:"noun",gender:"c",phonetic:"duh boyk",note:"De-word. 'Buikpijn' = stomachache.\n'Mijn buik doet pijn' = my belly hurts.\nAlternative: 'de maag' (the stomach, internal organ).",example:"A: Mijn buik doet pijn.\nB: Ik hoop dat je je snel beter voelt!\nA: Inderdaad.",exampleSrc:"A: My stomach hurts.\nB: I hope you feel better soon!\nA: Indeed.",funFact:"Belly / stomach. De-word. Native Germanic. Cognate with English 'bouk' (archaic body term). Also: 'buikpijn' (belly ache)."},
        {type:"teach",trg:"de rug",src:"the back",pos:"noun",gender:"c",phonetic:"duh rug",note:"De-word. 'Rugpijn' = back pain.\nVery common complaint in the Netherlands.\nRelated to German 'Rücken'.",example:"A: Ik heb rugpijn.\nB: Ik hoop dat je je snel beter voelt!\nA: Ja, precies!",exampleSrc:"A: I have back pain.\nB: I hope you feel better soon!\nA: Yes, exactly!",funFact:"Back (body part). From Proto-Germanic *hrukjaz. German 'Rücken' cognate. Idiom: 'de rug keren' (to turn one's back)."},
        {type:"teach",trg:"de hand",src:"the hand",pos:"noun",gender:"c",phonetic:"duh hant",note:"De-word. Identical to English!\nPlural: handen. Final -d sounds like -t.",example:"A: Geef me je hand.\nB: O, interessant!\nA: Ja, vind je niet?",exampleSrc:"A: Give me your hand.\nB: Oh, interesting!\nA: Yes, don't you think?",funFact:"Germanic cousin of English 'hand', German 'Hand'."},
        {type:"teach",trg:"de voet",src:"the foot",pos:"noun",gender:"c",phonetic:"duh foot",note:"De-word. Plural: voeten.\nSame root as English 'foot'. The 'oe' = 'oo'.",example:"A: Mijn voet doet pijn.\nB: Ik hoop dat je je snel beter voelt!\nA: Goed punt.",exampleSrc:"A: My foot hurts.\nB: I hope you feel better soon!\nA: Good point.",funFact:"Germanic cousin of English 'foot', German 'Fuß'."},
        {type:"teach",trg:"het been",src:"the leg",pos:"noun",gender:"n",phonetic:"hut bayn",note:"Het-word. ⚠️ False friend in English!\nDutch 'been' = leg (AND bone).\nEnglish 'bean' = Dutch 'boon'. Different word!",example:"A: Ik heb pijn in mijn been.\nB: Ik hoop dat je je snel beter voelt!\nA: Goed punt.",exampleSrc:"A: I have pain in my leg.\nB: I hope you feel better soon!\nA: Good point.",funFact:"Germanic cousin of English 'bone', German 'Bein'."},
        {type:"teach",trg:"de arm",src:"the arm",pos:"noun",gender:"c",phonetic:"duh arm",note:"De-word. Identical to English and German.\nPlural: armen.",example:"A: Mijn arm is gebroken.\nB: O, interessant!\nA: Ja, vind je niet?",exampleSrc:"A: My arm is broken.\nB: Oh, interesting!\nA: Yes, don't you think?",funFact:"Germanic cousin of English 'arm', German 'Arm'."},
        {type:"teach",trg:"het oor",src:"the ear",pos:"noun",gender:"n",phonetic:"hut ohr",note:"Het-word. Plural: oren.\nSame root as English 'ear' and German 'Ohr'.",example:"A: Ik heb pijn in mijn oor.\nB: Gaat het goed met je?\nA: Ja, precies!",exampleSrc:"A: I have pain in my ear.\nB: Are you doing okay?\nA: Yes, exactly!",funFact:"Germanic cousin of English 'ear', German 'Ohr'."},
        {type:"teach",trg:"het oog",src:"the eye",pos:"noun",gender:"n",phonetic:"hut ohg",note:"Het-word. Plural: ogen.\nThe 'g' in 'oog' is the Dutch throat sound.",example:"A: Mijn oog is rood.\nB: O, interessant!\nA: Ja, vind je niet?",exampleSrc:"A: My eye is red.\nB: Oh, interesting!\nA: Yes, don't you think?",funFact:"Germanic cousin of English 'eye', German 'Auge'."},
        {type:"teach",trg:"de keel",src:"the throat",pos:"noun",gender:"c",phonetic:"duh kayl",note:"De-word. 'Keelpijn' = sore throat.\nVery common winter complaint.",example:"A: Ik heb keelpijn.\nB: Gaat het goed met je?\nA: Goed punt.",exampleSrc:"A: I have a sore throat.\nB: Are you doing okay?\nA: Good point.",funFact:"Throat. De-word. Native Germanic. Cognate with English 'keel' (ship part; same 'trough' metaphor). Sore throat: 'keelpijn.'"},
        {type:"tip",title:"🏥 Compound Pain Words",text:"Dutch builds pain words by compounding:\n\nhoofdpijn = headache (hoofd + pijn)\nbuikpijn = stomachache\nrugpijn = back pain\nkeelpijn = sore throat\nkiespijn = toothache (kies = molar)\noorpijn = earache\n\nThe pattern: [body part] + pijn = [body part]-ache.\n\nAlternatively: 'Ik heb pijn in mijn [body part].'\nIk heb pijn in mijn been. = My leg hurts.\nIk heb pijn in mijn arm. = My arm hurts.\n\nOr: '[body part] doet pijn.' = [body part] hurts.\nMijn buik doet pijn. = My stomach hurts.\nMijn hoofd doet pijn. = My head hurts."},
        {type:"teach",trg:"de pijn",src:"the pain",pos:"noun",gender:"c",phonetic:"duh payn",note:"De-word. 'Pijn hebben' = to have pain.\n'Pijn doen' = to hurt.\nBoth constructions are equally common.",example:"A: Ik heb veel pijn.\nB: Ik hoop dat je je snel beter voelt!\nA: Ja, precies!",exampleSrc:"A: I have a lot of pain.\nB: I hope you feel better soon!\nA: Yes, exactly!",funFact:"Germanic cousin of English 'pain', French 'peine', German 'Pein'."},
        {type:"mc",q:"'Hoofdpijn' is a compound of:",opts:["hoofd + pijn = headache","hoof + dip = hoofache","hood + pijn = pain","hoofd + pin = needle"],ans:"hoofd + pijn = headache",hint:"Head + pain"},
        {type:"fb",opts:["pijn","ziek","koud","warm"],hint:"I have PAIN in my back",s:"Ik heb ___ in mijn rug.",a:"pijn"},
        {type:"match",pairs:[{trg:"het hoofd",src:"the head"},{trg:"de buik",src:"the belly"},{trg:"de rug",src:"the back"},{trg:"de voet",src:"the foot"}]},
        {type:"mc",q:"Dutch 'been' means:",opts:["bean","leg (and bone)","bin","behind"],ans:"leg (and bone)",hint:"False friend! Not a vegetable."},
        {type:"drag_fill",hint:"My belly hurts. I have a stomachache.",s:"Mijn {1} doet pijn. Ik heb {2}.",blanks:{"1":"buik","2":"buikpijn"},pool:["buik","buikpijn","hoofd","hoofdpijn"]},
        {type:"fb",opts:["keel","hoofd","oor","oog"],hint:"Throat + a word for hurting = sore throat",s:"Mijn ___ doet pijn. (throat)",a:"keel"},
        {type:"match",pairs:[{trg:"het oor",src:"the ear"},{trg:"het oog",src:"the eye"},{trg:"de hand",src:"the hand"},{trg:"de arm",src:"the arm"}]},
        {type:"mc",q:"Which body parts are het-words?",opts:["all body parts","arm, hand, rug, buik","hoofd, been, oor, oog","none of them"],ans:"hoofd, been, oor, oog",hint:"The paired/sensory ones tend to be het-words"},
        {type:"tr",mk:"u8_headache",dir:"produce"}
  ]},
  {id:"v2u8l1b",title:"Meer Lichaamsdelen",icon:"🦵",xp:18,board:true,steps:[
        {type:"intro",title:"Face, Neck, and More",desc:"het gezicht, de neus, de mond...\n\nExpanding your body vocabulary for the doctor and daily life.",goals:["Learn 8 more body parts with articles","Use them with 'pijn in mijn...'","Complete your A1 body vocabulary"]},
        {type:"teach",trg:"het gezicht",src:"the face",pos:"noun",gender:"n",phonetic:"hut guh-ZIKT",note:"Het-word. Cognate with German 'Gesicht'.\nAlso means 'vision' (gezichtsvermogen).",example:"A: Je gezicht is rood!\nB: Ja, ik was buiten in de zon.\nA: Gebruik zonnebrand!",exampleSrc:"A: Your face is red!\nB: Yes, I was outside in the sun.\nA: Use sunscreen!",funFact:"Face. Compound: ge- (collective) + zicht (sight, from zien). Literally 'that which is seen.' German 'Gesicht' same pattern."},
        {type:"teach",trg:"de neus",src:"the nose",pos:"noun",gender:"c",phonetic:"duh nuhs",note:"De-word. Cognate with English 'nose'.\nVerstopt = blocked/stuffed up.",example:"A: Mijn neus is verstopt.\nB: Heb je een verkoudheid?\nA: Ja, ik denk het.",exampleSrc:"A: My nose is stuffed.\nB: Do you have a cold?\nA: Yes, I think so.",funFact:"Germanic cousin of English 'nose', German 'Nase'."},
        {type:"teach",trg:"de mond",src:"the mouth",pos:"noun",gender:"c",phonetic:"duh mont",note:"De-word. Cognate with English 'mouth'.\nDoe je mond open = open your mouth.",example:"A: Doe je mond open.\nB: Aah!\nA: Je keel ziet er goed uit.",exampleSrc:"A: Open your mouth.\nB: Aah!\nA: Your throat looks fine.",funFact:"Germanic cousin of English 'mouth', German 'Mund'."},
        {type:"teach",trg:"de nek",src:"the neck (back)",pos:"noun",gender:"c",phonetic:"duh nek",note:"De-word. The BACK of the neck.\nDe keel = throat (front). De nek = neck (back).",example:"A: Ik heb pijn in mijn nek.\nB: Heb je achter de computer gezeten?\nA: Ja, de hele dag.",exampleSrc:"A: I have pain in my neck.\nB: Have you been sitting at the computer?\nA: Yes, all day.",funFact:"Germanic cousin of English 'neck', German 'Nacken'."},
        {type:"mc",q:"Het gezicht means:",opts:["the face","the view","the fight","the ghost"],ans:"the face",hint:"Cognate with German 'Gesicht'. Het-word."},
        {type:"teach",trg:"de schouder",src:"the shoulder",pos:"noun",gender:"c",phonetic:"duh SKHOW-dur",note:"De-word. Cognate with English 'shoulder'.\nLinks = left, rechts = right.",example:"A: Mijn schouder doet pijn.\nB: Links of rechts?\nA: De rechter schouder.",exampleSrc:"A: My shoulder hurts.\nB: Left or right?\nA: The right shoulder.",funFact:"Germanic cousin of English 'shoulder', German 'Schulter'."},
        {type:"teach",trg:"de tand",src:"the tooth",pos:"noun",gender:"c",phonetic:"duh tahnt",note:"De-word. Plural: tanden.\nDe tandarts = the dentist (tooth-doctor).\nKiespijn = toothache (kies = molar + pijn).",example:"A: Ik heb kiespijn.\nB: Ga naar de tandarts!\nA: Ja, dat moet ik doen.",exampleSrc:"A: I have a toothache.\nB: Go to the dentist!\nA: Yes, I should do that.",funFact:"Germanic cousin of English 'tooth', German 'Zahn'."},
        {type:"teach",trg:"de knie",src:"the knee",pos:"noun",gender:"c",phonetic:"duh k-NEE",note:"De-word. Same word as English 'knee'!\nThe 'k' is pronounced in Dutch (unlike English).",example:"A: Mijn knie doet pijn.\nB: Ben je gevallen?\nA: Ja, op straat.",exampleSrc:"A: My knee hurts.\nB: Did you fall?\nA: Yes, on the street.",funFact:"Germanic cousin of English 'knee'. Dutch and English are sister languages."},
        {type:"teach",trg:"de vinger",src:"the finger",pos:"noun",gender:"c",phonetic:"duh FING-ur",note:"De-word. Identical to English!\nPlural: vingers.",example:"A: Ik heb mijn vinger gesneden.\nB: Au! Met een mes?\nA: Ja, in de keuken.",exampleSrc:"A: I cut my finger.\nB: Ouch! With a knife?\nA: Yes, in the kitchen.",funFact:"Germanic cousin of English 'finger', German 'Finger'."},
        {type:"mc",q:"De tandarts means:",opts:["the tooth fairy","the dentist","the toothbrush","the toothache"],ans:"the dentist",hint:"Tand (tooth) + arts (doctor) = tooth-doctor = d..."},
        {type:"fb",opts:["nek","mond","neus","knie"],hint:"The back of your neck, sore from sitting at a computer.",s:"Ik heb pijn in mijn ___.\n(I have pain in my neck.)",a:"nek"},
        {type:"fb",opts:["mond","neus","oog","oor"],hint:"The doctor asks you to open this part of your face.",s:"Doe je ___ open.\n(Open your mouth.)",a:"mond"},
        {type:"match",pairs:[{trg:"het gezicht",src:"the face"},{trg:"de neus",src:"the nose"},{trg:"de mond",src:"the mouth"},{trg:"de nek",src:"the neck"}]},
        {type:"match",pairs:[{trg:"de schouder",src:"the shoulder"},{trg:"de tand",src:"the tooth"},{trg:"de knie",src:"the knee"},{trg:"de vinger",src:"the finger"}]},
        {type:"drag_fill",hint:"My shoulder hurts and I have neck pain.",s:"Mijn {1} doet pijn en ik heb {2}.",blanks:{"1":"schouder","2":"nekpijn"},pool:["schouder","nekpijn","knie","kiespijn"]},
        {type:"mc",q:"Which Dutch body part is a het-word?",opts:["de mond","de neus","het gezicht","de schouder"],ans:"het gezicht",hint:"Most body parts are de-words. ___ is the exception here."},
        {type:"mc",q:"De knie is special because:",opts:["It means 'knee' in German too","It's a het-word","It's not a cognate","The 'k' is pronounced in Dutch"],ans:"The 'k' is pronounced in Dutch",hint:"In English, 'knee' has a silent k. In ___, you hear the k."}
  ]},
  {id:"v2u8l2",title:"Ik Voel Me...",icon:"😊",xp:15,board:true,steps:[
        {type:"intro",title:"Ik Voel Me...",desc:"Dutch uses reflexive verbs for feelings. you learned the system in Unit 5. Now apply it to emotions and wellbeing. 'Ik voel me goed', 'ik voel me ziek', 'ik voel me moe'. essential daily vocabulary.",goals:["10 feeling/state adjectives","'Ik voel me...' for emotions","'Hoe gaat het?' deep dive","Nuanced responses beyond 'goed'"]},
        {type:"teach",trg:"ziek",src:"sick / ill",pos:"adj",gender:null,phonetic:"zeek",note:"Same root as English 'sick'. both from Proto-Germanic.\nGerman 'siech' still exists but only in literary or\nold-fashioned contexts; modern German uses 'krank' instead.\nDutch kept 'ziek' as the everyday word.\n'Ik ben ziek.' = I am sick.\n'Ik voel me ziek.' = I feel sick.\nAlso: 'het ziekenhuis' = the hospital (sick-house).",example:"A: Ik voel me ziek.\nB: Gaat het goed met je?\nA: Goed punt.",exampleSrc:"A: I feel sick.\nB: Are you doing okay?\nA: Good point.",funFact:"Germanic cousin of English 'sick', German 'siech (literary)'."},
        {type:"teach",trg:"moe",src:"tired",pos:"adj",gender:null,phonetic:"moo",note:"Short word, very common.\n'Ik voel me moe.' = I feel tired.\nGerman: müde. Same root.",example:"A: Ik ben heel moe.\nB: Ik hoop dat je je snel beter voelt!\nA: Inderdaad.",exampleSrc:"A: I am very tired.\nB: I hope you feel better soon!\nA: Indeed.",funFact:"Tired. From Proto-Germanic *mōþaz. German 'müde' with umlaut, Dutch without. 'Ik ben moe' (I am tired)."},
        {type:"teach",trg:"beter",src:"better",pos:"part",gender:null,phonetic:"BAY-tur",note:"Comparative of 'goed' (good).\ngoed → beter → best. Irregular!\nSame as English: good → better → best.",example:"A: Ik voel me vandaag beter.\nB: Misschien moet je naar de dokter.\nA: Inderdaad.",exampleSrc:"A: I feel better today.\nB: Maybe you should see a doctor.\nA: Indeed.",funFact:"Germanic cousin of English 'better', German 'besser'."},
        {type:"teach",trg:"lekker",src:"nice / well / tasty",pos:"adj",gender:null,phonetic:"LEK-kur",note:"'Lekker' = the Swiss army knife of Dutch.\nWith food: lekker = tasty. 'De kaas is lekker.'\nWith feelings: lekker = well/good. 'Ik voel me lekker.'\nNegative: 'niet lekker' = unwell, nauseous.",example:"A: Ik voel me niet lekker.\nB: Wil je er nog iets bij?\nA: Goed punt.",exampleSrc:"A: I don't feel well.\nB: Would you like anything else with that?\nA: Good point.",funFact:"Nice / well / tasty (u8 context). Reinforces u5 learning. Here broader: 'lekker geslapen' (slept well), 'lekker eten' (tasty food)."},
        {type:"teach",trg:"blij",src:"happy / glad",pos:"adj",gender:null,phonetic:"blay",note:"Short and common.\n'Blij met' = happy with/about.\n'Ik ben blij met mijn nieuwe baan.' = I'm happy with my new job.",example:"A: Ik ben heel blij!\nB: Wat leuk!\nA: Ja, inderdaad!",exampleSrc:"A: I am very happy!\nB: How nice!\nA: Yes, indeed!",funFact:"Happy / glad. Native Dutch. Short, positive adjective. 'Blij zijn' (to be happy). Opposite: verdrietig (sad)."},
        {type:"teach",trg:"verdrietig",src:"to be sad",pos:"verb",gender:null,phonetic:"fur-DREE-tug",note:"ver- + driet + -ig. 'Verdriet' = grief/sadness.\nMore formal; casual Dutch often says 'triest' or just 'niet blij'.",example:"A: Zij voelt zich verdrietig.\nB: O, dat wist ik niet.\nA: Nu wel!",exampleSrc:"A: She feels sad.\nB: Oh, I didn't know that.\nA: Now you do!",funFact:"To be sad. From 'verdriet' (sadness). 'Ver-' + 'drietig.' Sadness expressed as an intensified state."},
        {type:"teach",trg:"boos",src:"angry / mad",pos:"adj",gender:null,phonetic:"bohs",note:"'Boos op' = angry at (person).\n'Boos over' = angry about (thing).\nDutch directness: they'll tell you when they're boos.",example:"A: Hij is boos op mij.\nB: Ik begrijp het.\nA: Mooi zo!",exampleSrc:"A: He is angry at me.\nB: I understand.\nA: Good!",funFact:"Angry / mad. Native Dutch. Compare English 'boisterous' (same root). 'Boos zijn op' (to be angry at someone)."},
        {type:"teach",trg:"bang",src:"afraid / scared",pos:"adj",gender:null,phonetic:"bang",note:"'Bang voor' = afraid of.\nSame sound as English 'bang'!\n'Bang zijn' = to be afraid.",example:"A: Ik ben bang voor spinnen.\nB: Zal ik betalen?\nA: Klopt!",exampleSrc:"A: I'm afraid of spiders.\nB: Shall I pay?\nA: Right!",funFact:"Afraid / scared. Native Germanic. Cognate with archaic English 'bang' (blow/hit); the startle root."},
        {type:"tip",title:"💬 Beyond 'Goed': Real Answers to 'Hoe gaat het?'",text:"'Hoe gaat het?' → Dutch people usually say 'goed' or 'prima'.\nBut now you can be more expressive:\n\nPositive:\nHeel goed! = Very good!\nPrima! = Great!\nLekker! = Nice/well!\nIk voel me goed. = I feel good.\n\nNeutral:\nGaat wel. = It's okay. (most common honest answer)\nHet gaat. = It goes. (= surviving)\nNiet slecht. = Not bad.\n\nNegative:\nNiet zo goed. = Not so good.\nIk voel me niet lekker. = I don't feel well.\nIk ben moe. = I'm tired.\nIk ben een beetje ziek. = I'm a bit sick.\n\n'Gaat wel' is the real Dutch answer.\nIt means 'could be better, could be worse.'\nVery Dutch: understated, realistic, not dramatic."},
        {type:"mc",q:"'Ik voel me niet lekker' means:",opts:["I don't feel well","I don't feel tasty","I feel great","I'm not nice"],ans:"I don't feel well",hint:"lekker with feelings = w..."},
        {type:"fb",opts:["voel","ben","heb","ga"],hint:"I FEEL myself better today",s:"Ik ___ me vandaag beter.",a:"voel"},
        {type:"match",pairs:[{trg:"ziek",src:"sick"},{trg:"moe",src:"tired"},{trg:"blij",src:"happy"},{trg:"boos",src:"angry"}]},
        {type:"mc",q:"'Gaat wel' is the most Dutch answer because:",opts:["It's very positive","It's understated and realistic","It means 'excellent'","It's formal"],ans:"It's understated and realistic",hint:"Not too good, not too bad. Just... gaat wel."},
        {type:"drag_fill",hint:"Afraid OF spiders. Angry AT me.",s:"Ik ben {1} voor spinnen. Hij is {2} op mij.",blanks:{"1":"bang","2":"boos"},pool:["bang","boos","blij","moe"]},
        {type:"fb",opts:["zich","me","je","ons"],hint:"She feels HERSELF (third person reflexive)",s:"Zij voelt ___ verdrietig.",a:"zich"},
        {type:"mc",q:"'Lekker' can mean all EXCEPT:",opts:["tasty","well/good","expensive","nice"],ans:"expensive",hint:"A versatile word covering tasty, well, and nice"},
        {type:"fb",opts:["lekker","goed","blij","beter"],hint:"Use the Dutch verb for sensing/feeling + niet goed",s:"Ik voel me niet ___. Ik ben een beetje ziek.",a:"lekker"},
        {type:"tr",mk:"u8_feel_sick",dir:"produce"}
  ]},
  {id:"v2u8l3",title:"Bij de Huisarts",icon:"🩺",xp:20,board:true,steps:[
        {type:"intro",title:"Bij de Huisarts",desc:"The Dutch healthcare system starts with the huisarts (GP/family doctor). You can't go directly to a specialist. the huisarts decides. And their solution for almost everything? 'Neem maar een paracetamolletje.' This lesson teaches medical vocab and the cultural shock of Dutch healthcare.",goals:["Doctor visit vocabulary","Describe symptoms","Dutch healthcare culture","The huisarts gatekeeper system"]},
        {type:"teach",trg:"de huisarts",src:"the GP / family doctor",pos:"noun",gender:"c",phonetic:"duh HOYS-arts",note:"COMPOUND: huis + arts.\nhuis + arts = house + doctor.\nEvery Dutch person is registered with a huisarts.\nYou CANNOT see a specialist without a referral.",example:"A: Ik moet naar de huisarts.\nB: Ik hoop dat je je snel beter voelt!\nA: Ja, precies!",exampleSrc:"A: I have to go to the GP.\nB: I hope you feel better soon!\nA: Yes, exactly!",funFact:"Family doctor / GP. Compound: 'huis' (house) + 'arts' (doctor). Literally 'house-doctor.' Dutch healthcare: the huisarts is the entry point."},
        {type:"teach",trg:"de dokter",src:"the doctor",pos:"noun",gender:"c",phonetic:"duh DOK-tur",note:"General term. Less specific than 'huisarts'.\n'Naar de dokter gaan' = to go to the doctor.",example:"A: De dokter zegt dat ik moet rusten.\nB: Misschien moet je naar de dokter.\nA: Dat is zo.",exampleSrc:"A: The doctor says I must rest.\nB: Maybe you should see a doctor.\nA: That's true.",funFact:"international cousin of English 'doctor', German 'Doktor'."},
        {type:"teach",trg:"de afspraak",src:"the appointment",pos:"noun",gender:"c",phonetic:"duh AF-sprahk",note:"COMPOUND: af + spraak.\naf + spraak = appointment. Also: agreement.\n'Afspraak is afspraak' = a deal is a deal.\nYou need an afspraak for almost everything in NL.",example:"A: Ik heb een afspraak bij de huisarts.\nB: Gaat het goed met je?\nA: Goed punt.",exampleSrc:"A: I have an appointment at the GP.\nB: Are you doing okay?\nA: Good point.",funFact:"Appointment. Compound: 'af' (off/away) + 'spraak' (speech). Literally 'agreed-upon-speech.' A 'spoken agreement' become an appointment."},
        {type:"teach",trg:"het recept",src:"the prescription / recipe",pos:"noun",gender:"n",phonetic:"hut ruh-SEPT",note:"Het-word. Same word for recipe AND prescription!\nContext tells you which.\n'Een recept voor antibiotica' = a prescription for antibiotics.",example:"A: De dokter geeft een recept.\nB: Misschien moet je naar de dokter.\nA: Klopt!",exampleSrc:"A: The doctor gives a prescription.\nB: Maybe you should see a doctor.\nA: Right!",funFact:"international cousin of English 'receipt / recipe', German 'Rezept'."},
        {type:"tip",title:"🇳🇱 The Dutch Huisarts: Gatekeeper of Healthcare",deepDive:{
          title:"The paracetamolletje",
          text:"'Paracetamolletje'. note the diminutive (-letje)!\nIt makes the pill sound small, harmless, friendly.\n\nThe Dutch solution for:\n• Headache → paracetamolletje\n• Back pain → paracetamolletje\n• Flu → paracetamolletje + water + rest\n• Broken heart → paracetamolletje (joking... mostly)\n\nThis is a running joke among expats.\nBut the Dutch live to an average of 82 years.\nThe system works. Even if it frustrates you."
        },text:"The Dutch healthcare system works like this:\n\n1. You feel sick → call the huisarts\n2. Huisarts sees you (often same day or next day)\n3. Huisarts decides: treat, wait, or refer\n\nYou CANNOT:\n• Go directly to a specialist\n• Go to the ER for non-emergencies\n• Get antibiotics 'just in case'\n\nThe huisarts philosophy: the body heals itself.\nForeign residents are often shocked by:\n'Neem maar een paracetamolletje en drink veel water.'\n= Just take a paracetamol and drink lots of water.\n\nThis isn't neglect. it's evidence-based medicine.\nThe Dutch prescribe fewer antibiotics than almost\nany country in Europe. And their health outcomes\nare among the best."},
        {type:"teach",trg:"koorts",src:"fever",pos:"noun",gender:"c",phonetic:"kohrts",note:"De-word but often used without article.\n'Koorts hebben' = to have a fever.\n38°C+ = koorts in Dutch medical standards.",example:"A: Ik heb koorts.\nB: Ik hoop dat je je snel beter voelt!\nA: Dat is zo.",exampleSrc:"A: I have a fever.\nB: I hope you feel better soon!\nA: That's true.",funFact:"Germanic cousin of German 'Fieber (different word)'."},
        {type:"teach",trg:"verkouden",src:"having a cold",pos:"verb",gender:null,phonetic:"fur-KOW-dun",note:"Adjective, not a noun!\n'Ik BEN verkouden.' (with zijn, not hebben.)\n'Verkouden zijn' = to have a cold.",example:"A: Ik ben verkouden.\nB: Gaat het goed met je?\nA: Inderdaad.",exampleSrc:"A: I have a cold.\nB: Are you doing okay?\nA: Indeed.",funFact:"Having a cold. From 'koud' (cold) + 'ver-.' Literally 'over-cold' = suffering from cold. 'Ik ben verkouden' (I have a cold)."},
        {type:"teach",trg:"rusten",src:"to rest",pos:"verb",gender:null,phonetic:"RUS-tun",note:"Regular verb. Stam = rust.\nThe doctor's favorite advice after paracetamol:\n'Rust maar uit.' = Just rest.",example:"A: Je moet rusten.\nB: Misschien moet je naar de dokter.\nA: Inderdaad.",exampleSrc:"A: You must rest.\nB: Maybe you should see a doctor.\nA: Indeed.",funFact:"Germanic cousin of English 'rest', German 'ruhen / rasten'."},
        {type:"teach",trg:"de apotheek",src:"the pharmacy",pos:"noun",gender:"c",phonetic:"duh ah-poh-TAYK",note:"De-word. Where you pick up prescriptions.\n'De apotheker' = the pharmacist.\nOpen until 17:00-18:00, some have evening dienst.",example:"A: Ga naar de apotheek voor je recept.\nB: Dat is een goede keuze!\nA: Ja, precies!",exampleSrc:"A: Go to the pharmacy for your prescription.\nB: That's a good choice!\nA: Yes, exactly!",funFact:"international cousin of English 'apothecary', German 'Apotheke'."},
        {type:"mc",q:"In the Netherlands, you must see the huisarts before:",opts:["seeing a specialist","buying paracetamol","eating lunch","going to work"],ans:"seeing a specialist",hint:"The gatekeeper system. no direct access"},
        {type:"fb",opts:["ben","heb","voel","ga"],hint:"I AM having a cold (zijn, not hebben)",s:"Ik ___ verkouden.",a:"ben"},
        {type:"match",pairs:[{trg:"de huisarts",src:"the GP"},{trg:"de afspraak",src:"the appointment"},{trg:"het recept",src:"the prescription"},{trg:"de apotheek",src:"the pharmacy"}]},
        {type:"mc",q:"'Neem maar een paracetamolletje'. the '-letje' is:",opts:["a plural ending","a diminutive (making it sound small/friendly)","a formal suffix","the brand name"],ans:"a diminutive (making it sound small/friendly)",hint:"Unit 4 ___ system!"},
        {type:"drag_fill",hint:"I have a fever. Doctor says: rest.",s:"Ik heb {1}. De dokter zegt: je moet {2}.",blanks:{"1":"koorts","2":"rusten"},pool:["koorts","rusten","pijn","werken"]},
        {type:"fb",opts:["apotheek","huisarts","markt","winkel"],hint:"The pharmacy",s:"Ga naar de ___ voor je recept.",a:"apotheek"},
        {type:"mc",q:"The Dutch prescribe fewer ___ than most EU countries:",opts:["paracetamol","vitamins","antibiotics","coffee"],ans:"antibiotics",hint:"The body heals itself philosophy"},
        {type:"fb",opts:["afspraak","recept","pijn","koorts"],hint:"An appointment",s:"Ik heb een ___ bij de huisarts.",a:"afspraak"},
        {type:"tr",mk:"u8_go_to_doctor",dir:"produce"},
        {type:"tr",mk:"u8_take_paracetamol",dir:"produce"}
  ]},
  {id:"v2u8l4",title:"Doe Dit, Doe Dat",icon:"👆",xp:20,board:true,steps:[
        {type:"intro",title:"Doe Dit, Doe Dat",desc:"Commands in Dutch are dead simple: use the stam. 'Kom!' = Come! 'Ga zitten!' = Sit down! You've been seeing the stam for 7 units. now it has a new job. This lesson also teaches softening with 'maar', 'even', and 'eens'.",goals:["Form imperatives (= just the stam!)","Soften commands with maar/even/eens","Polite vs direct commands","Common imperative phrases"]},
        {type:"tip",title:"📐 The Imperative: Just the Stam",text:"The imperative in Dutch = the stam. That's it.\n\nwerken → werk! (Work!)\nkomen → kom! (Come!)\ngaan → ga! (Go!)\neten → eet! (Eat!)\nzitten → zit! (Sit!)\ndoen → doe! (Do!)\n\nYou already know the stam of every verb.\nNow you can give commands.\n\nFor separable verbs, the prefix goes to the end:\nopstaan → Sta op! (Stand up! / Get up!)\nbinnenkomen → Kom binnen! (Come in!)\nopbellen → Bel op! (Call!)\n\nFormality note: Dutch commands sound very direct.\nAdd 'u' for formal: 'Komt u binnen.' = Please come in.\nAdd softeners for polite: 'Kom maar binnen.' = Do come in."},
        {type:"teach",trg:"kom!",src:"come!",pos:"verb",gender:null,phonetic:"kom",note:"Stam of 'komen'. Simplest command.\n'Kom binnen!' = Come in!\n'Kom maar.' = Come on (encouraging).",example:"A: Kom hier!\nB: Veel plezier!\nA: Inderdaad.",exampleSrc:"A: Come here!\nB: Have fun!\nA: Indeed.",funFact:"Come! Imperative. Dutch imperatives use the stem form (drop -en). 'Kom' from 'komen.' No politeness marker needed for informal."},
        {type:"teach",trg:"ga!",src:"go!",pos:"verb",gender:null,phonetic:"gah",note:"Stam of 'gaan'.\n'Ga weg!' = Go away!\n'Ga maar.' = Go ahead.",example:"A: Ga zitten!\nB: Veel plezier!\nA: Inderdaad.",exampleSrc:"A: Sit down! (= Go sit!)\nB: Have fun!\nA: Indeed.",funFact:"Go! Imperative of 'gaan.' Irregular; short form. Parallel to English 'go!' Same intensity."},
        {type:"teach",trg:"wacht!",src:"wait!",pos:"verb",gender:null,phonetic:"vagt",note:"Stam of 'wachten'.\n'Wacht even' = wait a sec (very common).\n'Even' softens it dramatically.",example:"A: Wacht even!\nB: Dat klopt.\nA: Precies!",exampleSrc:"A: Wait a moment!\nB: That's right.\nA: Exactly!",funFact:"Wait! Imperative of 'wachten.' Regular stem: wacht-. 'Even wachten' (wait a moment) softer."},
        {type:"teach",trg:"kijk!",src:"look!",pos:"verb",gender:null,phonetic:"kayk",note:"Stam of 'kijken'.\n'Kijk uit!' = Watch out! / Be careful!\n'Kijk eens' = take a look (friendly).",example:"A: Kijk eens!\nB: Ik begrijp het.\nA: Mooi zo!",exampleSrc:"A: Look! / Check this out!\nB: I understand.\nA: Good!",funFact:"Look! Imperative of 'kijken.' Stem: kijk-. 'Kijk eens' (have a look) softer."},
        {type:"tip",title:"✨ Softeners: maar, even, eens",text:"Dutch commands can sound harsh. Add softeners:\n\nMAAR = go ahead, don't worry\n'Kom maar.' = Just come. (encouraging)\n'Ga maar zitten.' = Go ahead, sit down.\n'Neem maar.' = Just take it. (offering)\n\nEVEN = just, for a moment\n'Wacht even.' = Wait a sec.\n'Kijk even.' = Just take a look.\n'Kom even hier.' = Come here for a sec.\n\nEENS = why don't you (suggestion-like)\n'Kijk eens!' = Look! / Check this out!\n'Luister eens.' = Listen (for a moment).\n'Probeer eens.' = Try it!\n\nCombine them: 'Kom maar even hier.' = Just come here for a sec.\nThe more softeners, the more polite and gentle.\n\n⚠️ Without softeners, Dutch commands are VERY direct.\n'Kom!' vs 'Kom maar even.'. huge difference in tone."},
        {type:"teach",trg:"luister!",src:"listen!",pos:"verb",gender:null,phonetic:"LOYS-tur",note:"Stam of 'luisteren'.\n'Luister eens' = listen (gentle).\n'Luister goed' = listen carefully (firm).",example:"A: Luister goed!\nB: Interessant punt!\nA: Dat is zo.",exampleSrc:"A: Listen carefully!\nB: Interesting point!\nA: That's true.",funFact:"Close cousin of English 'listen!'. Both languages inherited this from their shared Germanic roots."},
        {type:"teach",trg:"neem",src:"take!",pos:"verb",gender:null,phonetic:"naym",note:"Stam of 'nemen'.\n'Neem maar.' = Go ahead and take it.\nVery common when offering food/drink.",example:"A: Neem maar een kopje koffie.\nB: Dat is een goede keuze!\nA: Inderdaad.",exampleSrc:"A: Just take/have a cup of coffee.\nB: That's a good choice!\nA: Indeed.",funFact:"Take. Imperative of 'nemen.' Regular stem: neem- (e → ee). Used in service contexts: 'neem er een' (take one)."},
        {type:"teach",trg:"stop!",src:"stop!",pos:"verb",gender:null,phonetic:"stop",note:"Stam of 'stoppen'. Identical to English.\n'Niet doen!' = Don't do (that)! very common.\nCombined: 'Stop daarmee!' = Stop that!",example:"A: Stop! Niet doen!\nB: Wat leuk!\nA: Ja, inderdaad!",exampleSrc:"A: Stop! Don't do that!\nB: How nice!\nA: Yes, indeed!",funFact:"international cousin of English 'stop', German 'Stopp'."},
        {type:"mc",q:"The Dutch imperative is formed by:",opts:["just using the stam","adding -en to the stam","using gaan + infinitive","adding -t to the stam"],ans:"just using the stam",hint:"Werk! Kom! Ga! = the ___"},
        {type:"fb",opts:["Ga","Gaat","Gaan","Ging"],hint:"Go ahead and sit! (stam of gaan)",s:"___ maar zitten!",a:"Ga"},
        {type:"mc",q:"'Wacht even' sounds softer than 'Wacht!' because:",opts:["'even' means please","'even' = just/for a moment. softens the command","it's a different verb","it's longer"],ans:"'even' = just/for a moment. softens the command",hint:"Softeners change the tone dramatically"},
        {type:"match",pairs:[{trg:"maar",src:"go ahead / just"},{trg:"even",src:"just / for a moment"},{trg:"eens",src:"why don't you (suggesting)"}]},
        {type:"drag_fill",hint:"Come here! Listen well!",s:"{1} hier! {2} goed!",blanks:{"1":"Kom","2":"Luister"},pool:["Kom","Luister","Gaat","Doen"]},
        {type:"fb",opts:["Neem","Neemt","Nemen","Genomen"],hint:"Just TAKE a cup of coffee",s:"___ maar een kopje koffie.",a:"Neem"},
        {type:"mc",q:"For separable verbs, the imperative puts the prefix:",opts:["before the stam: opsta!","nowhere: sta!","at the end: sta op!","doubled: opstaop!"],ans:"at the end: sta op!",hint:"Same as declarative: prefix to the ___"},
        {type:"fb",opts:["Kijk","Kijkt","Kijken","Gekeken"],hint:"Drop -en from the verb meaning 'to look' to find the stam",s:"___ uit! (= Watch out!)",a:"Kijk"},
        {type:"mc",q:"'Neem maar een paracetamolletje'. 'maar' here means:",opts:["but","never","more","go ahead / just (softener)"],ans:"go ahead / just (softener)",hint:"Encouraging: just take one, no worries"}
  ]},
  {id:"v2u8l5",title:"Groter, Beter, Mooier",icon:"📊",xp:20,board:true,steps:[
        {type:"intro",title:"Groter, Beter, Mooier",desc:"Bigger, better, more beautiful. Dutch comparatives add -er (like English) and use 'dan' (than). Simple system with a few spelling quirks. This lesson covers regular comparatives and the important irregulars.",goals:["Form comparatives with -er","Use 'dan' for comparison","Spelling changes with -er","4 irregular comparatives"]},
        {type:"tip",title:"📐 Comparatives: The Rule",text:"Dutch: adjective + -er + dan\nEnglish: adjective + -er + than\n\ngroot → groter dan = bigger than\nklein → kleiner dan = smaller than\nmooi → mooier dan = more beautiful than\noud → ouder dan = older than\n\nDutch NEVER uses 'meer' (more) for single adjectives.\nEnglish: 'more beautiful' ✓ / 'beautifuller' ✗\nDutch: 'mooier' ✓ / 'meer mooi' ✗\n\nEverything gets -er. Everything.\n(Except the 4 irregulars. see below.)"},
        {type:"teach",trg:"groter",src:"bigger / taller",pos:"adj",gender:null,phonetic:"GROH-tur",note:"groot → groter. The 'oo' becomes 'o'.\nWhy? 'gro-ter' = open syllable → one 'o' is enough.\nSame spelling rule as plurals!",example:"A: Amsterdam is groter dan Utrecht.\nB: Dat is goed om te weten.\nA: Ja, zeker!",exampleSrc:"A: Amsterdam is bigger than Utrecht.\nB: That's good to know.\nA: Yes, for sure!",funFact:"Bigger / taller. Comparative of 'groot' (big). -er is Dutch's comparative suffix, same as English."},
        {type:"teach",trg:"kleiner",src:"smaller",pos:"adj",gender:null,phonetic:"KLAY-nur",note:"klein → kleiner. No spelling change needed.\nThe diphthong 'ei' doesn't change.",example:"A: Utrecht is kleiner dan Amsterdam.\nB: Dat is goed om te weten.\nA: Ja, zeker!",exampleSrc:"A: Utrecht is smaller than Amsterdam.\nB: That's good to know.\nA: Yes, for sure!",funFact:"Smaller. Comparative of 'klein' (small). Regular -er ending. 'Ik ben kleiner dan jij' (I'm smaller than you)."},
        {type:"teach",trg:"mooier",src:"more beautiful / prettier",pos:"adj",gender:null,phonetic:"MOY-ur",note:"mooi → mooier. Just add -er.\nNo 'meer mooi'. Dutch always uses -er.",example:"A: Dit huis is mooier dan dat huis.\nB: Is het een groot huis?\nA: Dat is zo.",exampleSrc:"A: This house is prettier than that house.\nB: Is it a big house?\nA: That's true.",funFact:"More beautiful / prettier. Comparative of 'mooi.' Dutch adds -r to adjectives ending in unstressed syllables."},
        {type:"teach",trg:"dan",src:"than",pos:"adv",gender:null,phonetic:"dan",note:"'Dan' = than. Not 'als'!\n⚠️ Common mistake: 'groter als' (WRONG).\nCorrect: 'groter dan'. Always 'dan'.",example:"A: Kaas is duurder dan brood.\nB: Dat is een goede keuze!\nA: Klopt!",exampleSrc:"A: Cheese is more expensive than bread.\nB: That's a good choice!\nA: Right!",funFact:"Than. Comparative particle. 'Groter dan jij' (bigger than you). Cognate with English 'than.'"},
        {type:"teach",trg:"duurder",src:"more expensive",pos:"adj",gender:null,phonetic:"DUWR-dur",note:"duur → duurder. Regular -er.\nRemember from Unit 4: duur = expensive.",example:"A: Amsterdam is duurder dan Rotterdam.\nB: Zal ik betalen?\nA: Goed punt.",exampleSrc:"A: Amsterdam is more expensive than Rotterdam.\nB: Shall I pay?\nA: Good point.",funFact:"More expensive. Comparative of 'duur' (expensive). Note: 'duur' is the adjective; 'duurder' adds -der because of the preceding long vowel."},
        {type:"tip",title:"⚡ Irregular Comparatives",text:"Four common adjectives have irregular comparatives:\n\ngoed → beter (good → better)\nveel → meer (much/many → more)\nweinig → minder (little/few → less/fewer)\ngraag → liever (gladly → rather/preferring)\n\nThese are the SAME irregulars as English:\ngood → better (not 'gooder')\nmuch → more (not 'mucher')\nlittle → less (not 'littler')\n\nSame Germanic inheritance, same exceptions.\nJust four words to memorize."},
        {type:"teach",trg:"beter",src:"better",pos:"part",gender:null,phonetic:"BAY-tur",note:"goed → beter. Irregular.\nSame as English: good → better.\n'Beter laat dan nooit.' = Better late than never.",example:"A: Jouw koffie is beter dan mijn koffie.\nB: Wil je er nog iets bij?\nA: Dat is zo.",exampleSrc:"A: Your coffee is better than my coffee.\nB: Would you like anything else with that?\nA: That's true.",funFact:"Close cousin of English 'better'. Both languages inherited this from their shared Germanic roots."},
        {type:"teach",trg:"meer",src:"more",pos:"part",gender:null,phonetic:"mayr",note:"veel → meer. Irregular.\n'Meer dan' = more than.\n'Steeds meer' = increasingly.",example:"A: Ik wil meer koffie.\nB: Dat is een goede keuze!\nA: Ja, precies!",exampleSrc:"A: I want more coffee.\nB: That's a good choice!\nA: Yes, exactly!",funFact:"More. Irregular; not built from 'veel' (much). Cognate with English 'more' (Proto-Germanic 'maizon'). Foundational comparison word."},
        {type:"teach",trg:"minder",src:"less / fewer",pos:"part",gender:null,phonetic:"MIN-dur",note:"weinig → minder. Irregular.\n'Minder dan' = less/fewer than.\nOpposite of 'meer'.",example:"A: Ik heb minder tijd dan jij.\nB: O, is het al zo laat?\nA: Inderdaad.",exampleSrc:"A: I have less time than you.\nB: Oh, is it that late already?\nA: Indeed.",funFact:"Less / fewer. Paired with 'meer.' Dutch does NOT split into 'less/fewer' like English does; one word covers both counted and uncounted."},
        {type:"mc",q:"'Groot → groter'. the 'oo' becomes 'o' because:",opts:["Open syllable: one 'o' is enough for long vowel","It's irregular","Dutch hates double vowels","It's a spelling error"],ans:"Open syllable: one 'o' is enough for long vowel",hint:"gro-ter: ___ ___ = ___ ___ with one letter"},
        {type:"fb",opts:["groter","groot","grote","grooter"],hint:"Bigger than",s:"Amsterdam is ___ dan Utrecht.",a:"groter"},
        {type:"mc",q:"Dutch for 'more beautiful' is:",opts:["meer mooi","mooier","de meest mooi","het mooist"],ans:"mooier",hint:"Dutch ALWAYS uses -er, never 'meer + adjective'"},
        {type:"match",pairs:[{trg:"beter",src:"better"},{trg:"meer",src:"more"},{trg:"minder",src:"less"},{trg:"duurder",src:"more expensive"}]},
        {type:"drag_fill",hint:"Cheese is MORE EXPENSIVE. Your coffee is BETTER.",s:"Kaas is {1} dan brood. Jouw koffie is {2} dan mijn koffie.",blanks:{"1":"duurder","2":"beter"},pool:["duurder","beter","duur","goed"]},
        {type:"fb",opts:["minder","meer","weinig","veel"],hint:"I have LESS time than you",s:"Ik heb ___ tijd dan jij.",a:"minder"},
        {type:"mc",q:"The comparison word 'than' in Dutch is:",opts:["als","van","dan","met"],ans:"dan",hint:"Dutch comparison word meaning 'than'"},
        {type:"fb",opts:["beter","goeder","goeier","meer goed"],hint:"Irregular: good → better",s:"Goed → ___. Veel → meer.",a:"beter"},
        {type:"tr",mk:"u8_taller_than",dir:"produce"}
  ]},
  {id:"v2u8l6",title:"De Beste, De Grootste",icon:"🏆",xp:15,board:true,steps:[
        {type:"intro",title:"De Beste, De Grootste",desc:"The best, the biggest, the most beautiful. Dutch superlatives use -st (like English -est) with 'het' or 'de' before them. Combined with comparatives from L5, you can now rank and compare everything.",goals:["Form superlatives with -st/-ste","'De grootste' vs 'het grootst'","Irregular superlatives","Combine comparatives and superlatives"]},
        {type:"tip",title:"📐 Superlatives: The Rule",text:"Two forms:\n\n1. Before a noun: de/het + adjective + -ste\nDe grootste stad. = The biggest city.\nHet mooiste huis. = The most beautiful house.\n\n2. After 'is': het + adjective + -st (no -e)\nDeze stad is het grootst. = This city is the biggest.\nDit huis is het mooist. = This house is the most beautiful.\n\nAlways 'het' in the predicate form (after 'is'):\nAmsterdam is het grootst.\nNederlandse kaas is het lekkerst.\n\nIrregulars:\ngoed → best (not 'goedst')\nveel → meest (not 'veelst')\nweinig → minst (not 'weinigst')\ngraag → liefst (not 'graagst')"},
        {type:"teach",trg:"de grootste",src:"the biggest",pos:"noun",gender:"c",phonetic:"duh GROHT-stuh",note:"groot → grootst → grootste (before noun).\nDouble 'o' returns in closed syllable.\nBefore noun: add -e → grootste.",example:"A: Amsterdam is de grootste stad.\nB: Dat is goed om te weten.\nA: Ja, zeker!",exampleSrc:"A: Amsterdam is the biggest city.\nB: That's good to know.\nA: Yes, for sure!",funFact:"The biggest. De-word + superlative. Article de + adjective+ste + noun formula. Always with 'de' when superlative."},
        {type:"teach",trg:"de beste",src:"the best",pos:"noun",gender:"c",phonetic:"duh BES-tuh",note:"goed → best → beste (before noun).\nIrregular, same as English: good → best.\n'De beste' = the best.",example:"A: Dit is de beste kaas.\nB: Wil je er nog iets bij?\nA: Goed punt.",exampleSrc:"A: This is the best cheese.\nB: Would you like anything else with that?\nA: Good point.",funFact:"Germanic cousin of English 'best'. Dutch and English are sister languages."},
        {type:"teach",trg:"de mooiste",src:"the most beautiful",pos:"noun",gender:"c",phonetic:"duh MOY-stuh",note:"mooi → mooist → mooiste.\nNo 'meest mooi'. always -st.\nDutch: everything gets -st.",example:"A: De mooiste grachten zijn in Amsterdam.\nB: Waarom denk je dat?\nA: Inderdaad.",exampleSrc:"A: The most beautiful canals are in Amsterdam.\nB: Why do you think that?\nA: Indeed.",funFact:"The most beautiful. Superlative of 'mooi.' Regular -ste ending. Dutch superlatives always take 'de' with any noun gender."},
        {type:"teach",trg:"het meest",src:"the most",pos:"noun",gender:"n",phonetic:"hut mayst",note:"veel → meest. Irregular.\nSame as English: much → most.\n'De meeste mensen' = most people.",example:"A: Zij heeft het meest geleerd.\nB: Ik begrijp het.\nA: Mooi zo!",exampleSrc:"A: She learned the most.\nB: I understand.\nA: Good!",funFact:"The most. Het-word (neuter superlative). Used when the object/idea referred to is abstract. 'Het meest interessant' (the most interesting)."},
        {type:"teach",trg:"het minst",src:"the least",pos:"noun",gender:"n",phonetic:"hut minst",note:"weinig → minst. Irregular.\nOpposite of 'meest'.\n'De minste problemen' = the fewest problems.",example:"A: Dit kost het minst.\nB: Ik begrijp het.\nA: Mooi zo!",exampleSrc:"A: This costs the least.\nB: I understand.\nA: Good!",funFact:"The least. Het-word. Mirror of 'het meest.' Neuter-abstract superlative."},
        {type:"mc",q:"'De grootste stad'. 'grootste' is:",opts:["superlative before a noun","comparative","superlative after 'is'","imperative"],ans:"superlative before a noun",hint:"de + adjective + -ste = ___ ___"},
        {type:"fb",opts:["het","de","een","geen"],hint:"Which article precedes a superlative after 'is'?",s:"Nederlandse kaas is ___ lekkerst!",a:"het"},
        {type:"match",pairs:[{trg:"de beste",src:"the best"},{trg:"de grootste",src:"the biggest"},{trg:"het meest",src:"the most"},{trg:"het minst",src:"the least"}]},
        {type:"mc",q:"Dutch for 'the most beautiful' is:",opts:["de meest mooi","de mooiste","het meer mooi","mooist"],ans:"de mooiste",hint:"Always -ste, never 'meest + adjective'"},
        {type:"drag_fill",hint:"Superlative form: what comes after 'het'?",s:"Dit is {1} kaas. Amsterdam is {2} grootst.",blanks:{"1":"de beste","2":"het"},pool:["de beste","het","de","beter"]},
        {type:"fb",opts:["best","goedst","beter","meest goed"],hint:"Good → better → ?",s:"Goed → beter → ___.",a:"best"},
        {type:"mc",q:"After 'is', the superlative uses:",opts:["de + -ste","een + -ster","het + -st","no article"],ans:"het + -st",hint:"Superlatives after 'is' need a specific article"},
        {type:"fb",opts:["grootste","grootst","groter","groot"],hint:"Before noun: de + -ste",s:"Dit is de ___ stad van Nederland. (biggest)",a:"grootste"},
        {type:"tr",mk:"u8_best_cheese",dir:"produce"}
  ]},
  {id:"v2u8l7",title:"Hoe Gaat Het Echt?",icon:"💭",xp:15,board:true,steps:[
        {type:"intro",title:"Hoe Gaat Het Echt?",desc:"Pulling together body, feelings, health, commands, and comparatives in real conversation. How do you actually talk about health and feelings in Dutch daily life? This lesson is scenario-based: at work, at the doctor, with friends.",goals:["Natural health conversations","Combining grammar from L1,L6","Dutch directness about feelings","'Beterschap!' and other set phrases"]},
        {type:"teach",trg:"beterschap",src:"get well soon",pos:"intj",gender:null,phonetic:"BAY-tur-sgap",note:"The standard thing to say when someone is sick.\nLiterally: 'better-ship' (the state of getting better).\nJust one word. Simple and warm.",example:"A: Beterschap!\nB: Ik hoop dat je je snel beter voelt!\nA: Klopt!",exampleSrc:"A: Get well soon!\nB: I hope you feel better soon!\nA: Right!",funFact:"Get well soon. 'Beter' (better) + '-schap' (abstract noun suffix = -ship). Literally 'better-ship.' Formal well-wishing."},
        {type:"teach",trg:"sterkte",src:"be strong / good luck (with difficulty)",pos:"intj",gender:null,phonetic:"STAIRK-tuh",note:"From 'sterk' (strong) + -te.\nUsed when someone faces something hard:\nsickness, exams, bad news, a tough week.\n'Sterkte!' = hang in there / be strong.",example:"A: Sterkte met je examen!\nB: Veel succes met je studie!\nA: Dat is zo.",exampleSrc:"A: Good luck with your exam!\nB: Good luck with your studies!\nA: That's true.",funFact:"Be strong / good luck (with difficulty). 'Sterk' (strong) + '-te' (abstract noun = -ness). Used when facing hardship, not for casual good luck."},
        {type:"teach",trg:"succes",src:"good luck / success",pos:"intj",gender:null,phonetic:"suk-SES",note:"For neutral/positive situations.\n'Succes!' before a presentation, job interview, etc.\nCompare: 'sterkte' = for tough situations.",example:"A: Succes met je werk!\nB: Veel succes ermee!\nA: Klopt!",exampleSrc:"A: Good luck with your work!\nB: Good luck with it!\nA: Right!",funFact:"international cousin of English 'success', French 'succès'."},
        {type:"teach",trg:"gelukkig",src:"happy / fortunately",pos:"verb",gender:null,phonetic:"guh-LUK-kug",note:"Two meanings!\n1. Adjective: 'Ik ben gelukkig.' = I am happy.\n2. Adverb: 'Gelukkig is het niet erg.' = Fortunately it's not serious.\nContext tells you which.",example:"A: Gelukkig voel ik me beter.\nB: Misschien moet je naar de dokter.\nA: Ja, precies!",exampleSrc:"A: Fortunately I feel better.\nB: Maybe you should see a doctor.\nA: Yes, exactly!",funFact:"Happy / fortunately. Despite starting with ge-, NOT a participle; it's an adjective from 'geluk' (luck/fortune). Cognate with English 'lucky.'"},
        {type:"teach",trg:"helaas",src:"unfortunately",pos:"adv",gender:null,phonetic:"hay-LAHS",note:"The opposite of 'gelukkig' (fortunately).\nVery common in Dutch conversation.\n'Helaas niet.' = Unfortunately not.",example:"A: Helaas ben ik ziek.\nB: Ik hoop dat je je snel beter voelt!\nA: Goed punt.",exampleSrc:"A: Unfortunately I'm sick.\nB: I hope you feel better soon!\nA: Good point.",funFact:"Unfortunately. Composed of 'he' (alas) + 'laas' (sad, archaic). Native Germanic archaism preserved."},
        {type:"tip",title:"💬 Set Phrases for Health & Feelings",text:"When someone is sick:\n'Beterschap!' = Get well soon!\n'Pas goed op jezelf.' = Take good care of yourself.\n'Rust lekker uit.' = Rest well.\n\nWhen someone has a tough time:\n'Sterkte!' = Be strong / Hang in there.\n'Dat is vervelend.' = That's annoying/tough.\n'Kan ik iets doen?' = Can I do something?\n\nWhen something goes well:\n'Gefeliciteerd!' = Congratulations!\n'Goed gedaan!' = Well done!\n'Wat fijn!' = How nice!\n\nDutch directness extends to asking about health:\n'Je ziet er niet goed uit.' = You don't look well.\nThis isn't rude. it's concern. The Dutch show care\nby being direct, not by tiptoeing around things."},
        {type:"mc",q:"'Beterschap!' is used when someone is:",opts:["sick","getting married","going on vacation","starting a new job"],ans:"sick",hint:"Better-ship = get well soon"},
        {type:"fb",opts:["Succes","Sterkte","Beterschap","Gefeliciteerd"],hint:"Good luck (positive situation)",s:"___ met je examen!",a:"Succes"},
        {type:"mc",q:"'Sterkte' vs 'Succes'. what's the difference?",opts:["No difference","Sterkte = for tough situations, Succes = for neutral/positive","Sterkte is formal, Succes is informal","Sterkte is old-fashioned"],ans:"Sterkte = for tough situations, Succes = for neutral/positive",hint:"Unwell: say '___'. Exam: wish them good luck."},
        {type:"match",pairs:[{trg:"beterschap",src:"get well soon"},{trg:"sterkte",src:"hang in there"},{trg:"succes",src:"good luck"},{trg:"helaas",src:"unfortunately"}]},
        {type:"drag_fill",hint:"Unfortunately unwell. Fortunately better now.",s:"{1} ben ik ziek. {2} voel ik me beter.",blanks:{"1":"Helaas","2":"Gelukkig"},pool:["Helaas","Gelukkig","Beterschap","Sterkte"]},
        {type:"fb",opts:["gedaan","gemaakt","geweest","gegaan"],hint:"Well done! (past participle of doen)",s:"Goed ___!",a:"gedaan"},
        {type:"mc",q:"'Je ziet er niet goed uit' is:",opts:["an insult","a compliment","Dutch direct concern about your health","a greeting"],ans:"Dutch direct concern about your health",hint:"___ness = care in ___ culture"},
        {type:"fb",opts:["Gelukkig","Helaas","Beterschap","Sterkte"],hint:"Fortunately...",s:"___ is het niet erg. (= Fortunately it's not serious.)",a:"Gelukkig"},
        {type:"tr",mk:"u8_feel_sick",dir:"produce"},
        {type:"tr",mk:"u8_headache",dir:"produce"}
  ]},
  {id:"v2u8l8",title:"Unit 8 Review",icon:"🔄",xp:20,board:true,steps:[
        {type:"intro",title:"Unit 8: Alles Samen",desc:"Body parts, feelings, the huisarts, imperatives, comparatives, superlatives, and Dutch directness about health. All mixed together. The scenario: you're not feeling well, you visit the doctor, and things get better.",goals:["Body parts and pain compounds","Feelings and wellbeing","Imperatives with softeners","Comparatives and superlatives","Healthcare culture"]},
        {type:"tip",title:"📋 What You Know Now",text:"After Unit 8 you can:\n\n• Name 12 body parts\n• Describe pain with compounds (hoofdpijn, rugpijn)\n• Express 8 feelings (ziek, moe, blij, boos...)\n• Navigate a huisarts visit\n• Give commands with softeners (maar, even, eens)\n• Compare things (groter dan, beter dan)\n• Use superlatives (de beste, het grootst)\n• Use set phrases (beterschap, sterkte, succes)\n\nYou're solidly A2.1 now."},
        {type:"mc",q:"'Ik heb buikpijn' is a compound of:",opts:["buik + pijn = stomachache","bui + kpijn = stormache","buik + pin = belly pin","boek + pijn = bookache"],ans:"buik + pijn = stomachache",hint:"Belly + pain"},
        {type:"fb",opts:["lekker","goed","groot","mooi"],hint:"Express feeling unwell using 'voelen'",s:"Ik voel me niet ___.",a:"lekker"},
        {type:"mc",q:"The imperative of 'komen' is:",opts:["komt!","kom!","komen!","gekomen!"],ans:"kom!",hint:"Imperative = stam"},
        {type:"match",pairs:[{trg:"beterschap",src:"get well soon"},{trg:"sterkte",src:"hang in there"},{trg:"groter dan",src:"bigger than"},{trg:"de beste",src:"the best"}]},
        {type:"drag_fill",hint:"Comparative uses 'dan'. Superlative uses 'het' + what?",s:"Amsterdam is {1} dan Utrecht. Nederlandse kaas is {2} beste.",blanks:{"1":"groter","2":"de"},pool:["groter","de","groot","het"]},
        {type:"fb",opts:["Wacht","Wachten","Gewacht","Wachtte"],hint:"Wait a moment! (imperative)",s:"___ even! Ik kom eraan.",a:"Wacht"},
        {type:"mc",q:"At the huisarts, you're most likely to hear:",opts:["Hier is een recept voor antibiotica.","U moet naar het ziekenhuis.","Neem maar een paracetamolletje.","Ik weet het niet."],ans:"Neem maar een paracetamolletje.",hint:"The Dutch healthcare philosophy"},
        {type:"fb",opts:["best","goedst","betest","meest goed"],hint:"Good → better → ...",s:"Goed → beter → ___.",a:"best"},
        {type:"mc",q:"After 'is', the superlative always uses:",opts:["de","geen","een","het"],ans:"het",hint:"Predicative superlatives always use the neuter article, regardless of noun gender"},
        {type:"drag_fill",hint:"I have a headache. Doctor says: just rest!",s:"Ik heb {1}. De dokter zegt: {2} maar uit!",blanks:{"1":"hoofdpijn","2":"Rust"},pool:["hoofdpijn","Rust","koorts","Neem"]},
        {type:"mc",q:"'Gelukkig' can mean:",opts:["both 'happy' and 'fortunately'","only 'fortunately'","only 'happy'","'unlucky'"],ans:"both 'happy' and 'fortunately'",hint:"Two meanings depending on context"},
        {type:"fb",opts:["Succes","Sterkte","Beterschap","Proost"],hint:"Good luck (positive occasion)",s:"___ met je examen!",a:"Succes"},
        {type:"match",pairs:[{trg:"het hoofd",src:"the head"},{trg:"de buik",src:"the belly"},{trg:"de rug",src:"the back"},{trg:"de keel",src:"the throat"}]},
        {type:"mc",q:"'Minder' is the comparative of:",opts:["meer","weinig","minder","klein"],ans:"weinig",hint:"Which word means 'little' or 'few'?"},
        {type:"drag_fill",hint:"Unfortunately... Fortunately...",s:"{1} ben ik ziek. {2} voel ik me vandaag beter.",blanks:{"1":"Helaas","2":"Gelukkig"},pool:["Helaas","Gelukkig","Sterkte","Beterschap"]},
        {type:"tr",mk:"u8_go_to_doctor",dir:"produce"},
        {type:"tr",mk:"u8_best_cheese",dir:"produce"},
        {type:"tr",mk:"u8_taller_than",dir:"produce"}
  ]},
  {id:"v2u8l8b",title:"Dieren",icon:"🐶",xp:20,board:true,steps:[
        {type:"intro",title:"Dieren",desc:"Learn the names of common animals in Dutch. Many Dutch animal words are cognates of English or German words. You will also learn which animals are de-words and which are het-words.",goals:["Learn 12 common animal names with de/het","Distinguish between de-words and het-words for animals","Talk about pets and wildlife"]},
        {type:"teach",trg:"de hond",src:"the dog",pos:"noun",gender:"c",phonetic:"duh HONT",note:"De-word. Plural: honden.\nCognate with English 'hound' and German 'Hund'.",example:"A: Heb je een hond?\nB: Ja, ik heb een kleine hond.\nA: Hoe heet hij?\nB: Hij heet Max.",exampleSrc:"A: Do you have a dog?\nB: Yes, I have a small dog.\nA: What is his name?\nB: His name is Max.",funFact:"Germanic cousin of English 'hound', German 'der Hund'.",deepDive:{
          title:"Dog Expressions",
          text:"Useful phrases:\nde hond uitlaten = to walk the dog\nhondenweer = dog weather (terrible weather)\nzo ziek als een hond = as sick as a dog"
        }},
        {type:"teach",trg:"de kat",src:"the cat",pos:"noun",gender:"c",phonetic:"duh KAHT",note:"De-word. Plural: katten.\nDirect cognate with English 'cat'.",example:"A: Onze kat slaapt de hele dag.\nB: Dat doen katten!\nA: Ja, ze is heel lui.\nB: Maar ook lief.",exampleSrc:"A: Our cat sleeps all day.\nB: That's what cats do!\nA: Yes, she is very lazy.\nB: But also sweet.",funFact:"Germanic cousin of English 'cat', German 'die Katze'."},
        {type:"teach",trg:"de vogel",src:"the bird",pos:"noun",gender:"c",phonetic:"duh FOH-gul",note:"De-word. Plural: vogels.\nCognate with English 'fowl' and German 'Vogel'.",example:"A: Hoor je die vogel?\nB: Ja, hij zingt mooi.\nA: Het is een merel.\nB: Wat een mooi geluid!",exampleSrc:"A: Do you hear that bird?\nB: Yes, it sings beautifully.\nA: It is a blackbird.\nB: What a nice sound!",funFact:"Germanic cousin of English 'fowl', German 'der Vogel'."},
        {type:"teach",trg:"de vis",src:"the fish",pos:"noun",gender:"c",phonetic:"duh FIS",note:"De-word. Plural: vissen.\nCognate with English 'fish' and German 'Fisch'.",example:"A: Eet je graag vis?\nB: Ja, vooral haring.\nA: Typisch Nederlands!\nB: Haring is lekker!",exampleSrc:"A: Do you like eating fish?\nB: Yes, especially herring.\nA: Typical Dutch!\nB: Herring is delicious!",funFact:"Germanic cousin of English 'fish', German 'der Fisch'."},
        {type:"teach",trg:"het konijn",src:"the rabbit",pos:"noun",gender:"n",phonetic:"hut koh-NINE",note:"Het-word. Plural: konijnen.\nA very popular pet in the Netherlands.",example:"A: We hebben twee konijnen.\nB: Als huisdier?\nA: Ja, ze zijn heel lief.\nB: Leuk! Hoe heten ze?",exampleSrc:"A: We have two rabbits.\nB: As pets?\nA: Yes, they are very sweet.\nB: Nice! What are their names?",funFact:"Rabbit. Het-word. Loanword from Latin 'cuniculus' (same root as Spanish 'conejo'). Compare to 'de haas' (the hare) which is de-word."},
        {type:"teach",trg:"het paard",src:"the horse",pos:"noun",gender:"n",phonetic:"hut PAHRT",note:"Het-word. Plural: paarden.\nPaardrijden = horse riding (one word).",example:"A: Kun je paardrijden?\nB: Ja, ik rijd elke week.\nA: Waar doe je dat?\nB: Op een manege buiten de stad.",exampleSrc:"A: Can you ride horses?\nB: Yes, I ride every week.\nA: Where do you do that?\nB: At a riding school outside the city.",funFact:"Horse. Het-word. Native Germanic. Contrast with English 'horse' (from different root). Dutch preserves older 'paard' ~ German 'Pferd.'"},
        {type:"teach",trg:"de koe",src:"the cow",pos:"noun",gender:"c",phonetic:"duh KOO",note:"De-word. Plural: koeien.\nCognate with English 'cow' and German 'Kuh'.",example:"A: Kijk, koeien in de wei!\nB: Typisch Nederlands landschap.\nA: Ja, koeien en molens.\nB: En fietsen!",exampleSrc:"A: Look, cows in the meadow!\nB: Typical Dutch landscape.\nA: Yes, cows and windmills.\nB: And bicycles!",funFact:"Germanic cousin of English 'cow', German 'die Kuh'."},
        {type:"teach",trg:"het varken",src:"the pig",pos:"noun",gender:"n",phonetic:"hut FAR-kun",note:"Het-word. Plural: varkens.\nVarkensvlees = pork (pig-meat).",example:"A: Het varken is een slim dier.\nB: Slimmer dan een hond?\nA: Sommige mensen denken van wel.\nB: Interessant!",exampleSrc:"A: The pig is a smart animal.\nB: Smarter than a dog?\nA: Some people think so.\nB: Interesting!",funFact:"Pig. Het-word. Diminutive form of archaic 'var' (male pig). Always het because of the diminutive history."},
        {type:"teach",trg:"de kip",src:"the chicken",pos:"noun",gender:"c",phonetic:"duh KIP",note:"De-word. Plural: kippen.\nKippensoep = chicken soup.",example:"A: Wij hebben kippen in de tuin.\nB: Leggen ze eieren?\nA: Ja, elke dag twee of drie.\nB: Vers ontbijt!",exampleSrc:"A: We have chickens in the garden.\nB: Do they lay eggs?\nA: Yes, two or three every day.\nB: Fresh breakfast!",funFact:"Chicken. De-word. Dutch-specific; German says 'Huhn,' English 'chicken.' 'Kip' is onomatopoeic of bird sound."},
        {type:"teach",trg:"het schaap",src:"the sheep",pos:"noun",gender:"n",phonetic:"hut SKHAHP",note:"Het-word. Plural: schapen.\nCognate with German 'Schaf'.",example:"A: Er zijn veel schapen in Nederland.\nB: Ja, vooral op de dijk.\nA: Ze eten het gras kort.\nB: Dat is handig!",exampleSrc:"A: There are many sheep in the Netherlands.\nB: Yes, especially on the dike.\nA: They keep the grass short.\nB: That is handy!",funFact:"Sheep. From Proto-Germanic *skēpą. Plural: schapen (unusual -en plural). Idiom: 'zwart schaap' (black sheep of the family)."},
        {type:"teach",trg:"het dier",src:"the animal",pos:"noun",gender:"n",phonetic:"hut DEER",note:"Het-word. Plural: dieren.\nLievelingsdier = favorite animal.\nCognate with German 'Tier'.",example:"A: Wat is je lievelingsdier?\nB: De hond. En jij?\nA: Ik vind katten leuker.\nB: Allebei leuk!",exampleSrc:"A: What is your favorite animal?\nB: The dog. And you?\nA: I prefer cats.\nB: Both are nice!",funFact:"Germanic cousin of English 'deer', German 'das Tier'."},
        {type:"teach",trg:"het huisdier",src:"the pet",pos:"noun",gender:"n",phonetic:"hut HOWS-deer",note:"COMPOUND: huis (house) + dier (animal).\nHet-word. Huis (house) + dier (animal) = huisdier.\nPlural: huisdieren.",example:"A: Heb je huisdieren?\nB: Ja, een kat en een konijn.\nA: Dat is gezellig!\nB: Ze zijn als familie.",exampleSrc:"A: Do you have pets?\nB: Yes, a cat and a rabbit.\nA: That is cozy!\nB: They are like family.",funFact:"Pet. Het-word. Compound: 'huis' (house) + 'dier' (animal). Literally 'house-animal.' Compound inherits 'dier' gender (het)."},
        {type:"tip",title:"De or Het? Animal Patterns",text:"Most animals are de-words:\nde hond, de kat, de vogel, de vis, de koe, de kip\n\nSome important het-words:\nhet konijn, het paard, het varken, het schaap, het dier\n\nYoung animals are almost always het-words:\nhet lam (lamb), het kuiken (chick), het veulen (foal)\n\nCompound animal nouns:\nhuisdier = pet (huis + dier)\ndierentuin = zoo (dieren + tuin = animal garden)"},
        {type:"mc",q:"Which of these animals is a het-word?",opts:["het konijn","de hond","de kat","de vogel"],ans:"het konijn",hint:"Think of the animal that hops. Not all animals are de-words."},
        {type:"mc",q:"'De koe' is a cognate of which English word?",opts:["coat","cow","cook","coke"],ans:"cow",hint:"A farm animal that gives milk. Same Germanic root."},
        {type:"fb",opts:["kippen","katten","koeien","konijnen"],hint:"Clucking animals that lay eggs in the garden.",s:"Wij hebben twee ___ in de tuin.\n(We have two chickens in the garden.)",a:"kippen"},
        {type:"mc",q:"'Varkensvlees' means:",opts:["chicken","beef","pork","lamb"],ans:"pork",hint:"Varken (pig) + vlees (meat) = pig meat."},
        {type:"fb",opts:["dier","hond","huisdier","beest"],hint:"The general word for 'animal'. Het-word.",s:"Mijn lievelings___ is de hond.\n(My favorite animal is the dog.)",a:"dier"},
        {type:"match",pairs:[{trg:"de hond",src:"the dog"},{trg:"het konijn",src:"the rabbit"},{trg:"het paard",src:"the horse"},{trg:"de koe",src:"the cow"},{trg:"het schaap",src:"the sheep"}]},
        {type:"drag_fill",hint:"I have a cat and a rabbit as pets.",s:"Ik heb een {1} en een {2} als {3}.",blanks:{"1":"kat","2":"konijn","3":"huisdier"},pool:["kat","konijn","huisdier","dierentuin"]},
        {type:"mc",q:"Which sentence is correct?",opts:["De paard is een grote dier.","De paard is een groot dier.","Het paard is een grote dier.","Het paard is een groot dier."],ans:"Het paard is een groot dier.",hint:"This animal is neuter: indefinite neuter nouns take no -e on the adjective"}
  ]},
  {id:"v2u8l8c",title:"Gezondheid",icon:"💊",xp:20,board:true,steps:[
        {type:"intro",title:"Gezondheid",desc:"Learn essential health vocabulary for visiting a doctor, going to the pharmacy, or describing how you feel. These words will help you navigate Dutch healthcare.",goals:["Learn 12 health-related words with de/het","Describe symptoms and illnesses","Talk about medicine and healthcare"]},
        {type:"teach",trg:"ziek",src:"sick / ill",pos:"adj",gender:null,phonetic:"zeek",note:"Adjective. Ik ben ziek = I am sick.\nIk voel me ziek = I feel sick.\nCognate with English 'sick'.",example:"A: Ik voel me ziek.\nB: Wat heb je?\nA: Ik heb koorts en hoofdpijn.\nB: Ga naar de dokter!",exampleSrc:"A: I feel sick.\nB: What do you have?\nA: I have a fever and headache.\nB: Go to the doctor!",funFact:"Germanic cousin of English 'sick', German 'siech (archaic)'."},
        {type:"teach",trg:"de koorts",src:"the fever",pos:"noun",gender:"c",phonetic:"duh KOHRTS",note:"De-word. Dutch uses Celsius.\n38,5 graden = fever. 36,5 = normal.\nNote: Dutch uses a comma for decimals.",example:"A: Heb je koorts?\nB: Ja, 38,5 graden.\nA: Dat is best hoog.\nB: Ik neem een paracetamol.",exampleSrc:"A: Do you have a fever?\nB: Yes, 38.5 degrees.\nA: That is quite high.\nB: I will take a paracetamol.",funFact:"Fever. De-word. Cognate with English 'cold' (same Germanic root; fevers and colds share etymology as body-state shifts)."},
        {type:"teach",trg:"de hoest",src:"the cough",pos:"verb",gender:null,phonetic:"duh HOOST",note:"De-word. Also a verb: hoesten = to cough.\nIk hoest = I cough. Je hoest = you cough.",example:"A: Je hoest veel.\nB: Ja, al drie dagen.\nA: Drink warme thee met honing.\nB: Goed idee, dankjewel.",exampleSrc:"A: You cough a lot.\nB: Yes, for three days already.\nA: Drink warm tea with honey.\nB: Good idea, thank you.",funFact:"The cough. De-word (common gender). From 'hoesten' (to cough). Noun derived from verb; transparent pattern."},
        {type:"teach",trg:"de verkoudheid",src:"the cold (illness)",pos:"noun",gender:"c",phonetic:"duh fur-KOWD-hite",note:"De-word. From 'verkouden' (having a cold).\nVerkouden zijn = to have a cold.\n-heid suffix = English '-ness'.",example:"A: Ik heb een verkoudheid.\nB: Neem rust en drink veel water.\nA: Moet ik naar de dokter?\nB: Nee, het gaat vanzelf over.",exampleSrc:"A: I have a cold.\nB: Rest and drink lots of water.\nA: Should I go to the doctor?\nB: No, it will pass on its own.",funFact:"Cold (illness). De-word. Abstract noun from 'verkouden' (having a cold) + '-heid' suffix (abstractness). 'I have a cold': 'Ik ben verkouden.'"},
        {type:"teach",trg:"de hoofdpijn",src:"the headache",pos:"noun",gender:"c",phonetic:"duh HOHFT-pine",note:"COMPOUND: hoofd (head) + pijn (pain).\nDe-word. Hoofd (head) + pijn (pain).\nSame pattern: buikpijn, rugpijn, keelpijn.",example:"A: Ik heb hoofdpijn.\nB: Wil je een paracetamol?\nA: Ja, graag.\nB: Hier, met een glas water.",exampleSrc:"A: I have a headache.\nB: Do you want a paracetamol?\nA: Yes, please.\nB: Here, with a glass of water.",funFact:"Headache. De-word. Compound: 'hoofd' (head) + 'pijn' (pain). Transparent compound. Dutch makes medical terms accessible."},
        {type:"teach",trg:"het medicijn",src:"the medicine",pos:"noun",gender:"n",phonetic:"hut may-dee-SINE",note:"Het-word. Plural: medicijnen.\nMedicijn nemen = to take medicine.\nCognate with English 'medicine'.",example:"A: Neem je medicijnen?\nB: Ja, twee keer per dag.\nA: Vergeet het niet!\nB: Nee, ik zet een alarm.",exampleSrc:"A: Do you take medicine?\nB: Yes, twice a day.\nA: Don't forget it!\nB: No, I set an alarm.",funFact:"Germanic cousin of English 'medicine'. Dutch and English are sister languages."},
        {type:"teach",trg:"het ziekenhuis",src:"the hospital",pos:"noun",gender:"n",phonetic:"hut ZEE-kun-hows",note:"COMPOUND: zieken (sick) + huis (house).\nHet-word. Ziek (sick) + huis (house) = sick-house.\nIn het ziekenhuis liggen = to be in hospital.",example:"A: Mijn oma ligt in het ziekenhuis.\nB: Wat is er gebeurd?\nA: Ze is gevallen.\nB: Beterschap!",exampleSrc:"A: My grandma is in the hospital.\nB: What happened?\nA: She fell.\nB: Get well soon!",funFact:"Hospital. Het-word. Compound: 'zieken' (sick-plural) + 'huis' (house). Literally 'sick-people's house.' Compound inherits 'huis' gender."},
        {type:"teach",trg:"de apotheek",src:"the pharmacy",pos:"noun",gender:"c",phonetic:"duh ah-poh-TAKE",note:"De-word. Cognate with English 'apothecary'.\nDe apotheker = the pharmacist.",example:"A: Ik moet naar de apotheek.\nB: Heb je een recept?\nA: Ja, van de dokter.\nB: De apotheek is om de hoek.",exampleSrc:"A: I need to go to the pharmacy.\nB: Do you have a prescription?\nA: Yes, from the doctor.\nB: The pharmacy is around the corner.",funFact:"Pharmacy. De-word. Greek loan via Latin 'apothēca' (storehouse). Same root as English 'apothecary.'"},
        {type:"teach",trg:"het recept",src:"the prescription",pos:"noun",gender:"n",phonetic:"hut ruh-SEPT",note:"Het-word. Also means 'recipe' (cooking).\nEen recept schrijven = to write a prescription.",example:"A: De dokter schrijft een recept.\nB: Voor welk medicijn?\nA: Antibiotica.\nB: Haal het bij de apotheek.",exampleSrc:"A: The doctor writes a prescription.\nB: For which medicine?\nA: Antibiotics.\nB: Pick it up at the pharmacy.",funFact:"Recipe / prescription. Het-word. From Latin 'receptum.' Dual meaning: cooking recipe AND medical prescription. Same word for both."},
        {type:"teach",trg:"de allergie",src:"the allergy",pos:"noun",gender:"c",phonetic:"duh ah-lur-GHEE",note:"De-word. Allergisch = allergic.\nIk ben allergisch voor... = I am allergic to...\nCognate with English 'allergy'.",example:"A: Ik heb een allergie voor noten.\nB: Echt waar? Dat is erg!\nA: Ja, ik moet oppassen.\nB: Heb je medicijnen bij je?",exampleSrc:"A: I have an allergy to nuts.\nB: Really? That's bad!\nA: Yes, I have to be careful.\nB: Do you have medicine with you?",funFact:"Germanic cousin of English 'allergy'. Dutch and English are sister languages."},
        {type:"tip",title:"Bij de Dokter",text:"Useful phrases at the doctor:\n\nIk voel me niet lekker. = I don't feel well.\nIk heb pijn in mijn... = I have pain in my...\nHoe lang heb je dit al? = How long have you had this?\nHeeft u allergieën? = Do you have allergies? (formal)\nIk heb een afspraak. = I have an appointment.\n\nThe Dutch GP is called 'de huisarts' (house doctor).\nYou always visit your huisarts FIRST.\nThey refer you to a specialist if needed."},
        {type:"mc",q:"'Het ziekenhuis' literally translates to:",opts:["the sick house","the health center","the doctor's office","the medicine building"],ans:"the sick house",hint:"Break it down: ziek (___) + huis (___)."},
        {type:"mc",q:"Which word means 'prescription' AND 'recipe'?",opts:["het medicijn","het recept","de apotheek","de koorts"],ans:"het recept",hint:"This word is a cognate with English, borrowed from Latin"},
        {type:"fb",opts:["allergisch","ziek","verkouden","moe"],hint:"The adjective derived from 'allergie': describes a reaction to triggers like cats, pollen, or nuts",s:"Ik ben ___ voor katten.\n(I am allergic to cats.)",a:"allergisch"},
        {type:"mc",q:"Where do you get your medicine in the Netherlands?",opts:["de huisarts","het ziekenhuis","de apotheek","de supermarkt"],ans:"de apotheek",hint:"Cognate with English 'apothecary'. The place that fills prescriptions."},
        {type:"fb",opts:["koorts","pijn","ziek","koud"],hint:"High temperature. Measured in degrees Celsius.",s:"Ik heb ___ en hoest.\n(I have a fever and a cough.)",a:"koorts"},
        {type:"match",pairs:[{trg:"de koorts",src:"the fever"},{trg:"de hoest",src:"the cough"},{trg:"de hoofdpijn",src:"the headache"},{trg:"het medicijn",src:"the medicine"}]},
        {type:"drag_fill",hint:"I am sick and have a fever. I go to the doctor.",s:"Ik ben {1} en heb {2}. Ik ga naar de {3}.",blanks:{"1":"ziek","2":"koorts","3":"dokter"},pool:["ziek","koorts","dokter","apotheek"]},
        {type:"mc",q:"'Ik voel me niet lekker' means:",opts:["I am not delicious","I don't taste nice","I don't like the food","I don't feel well"],ans:"I don't feel well",hint:"'Lekker' has many meanings. Here it means 'w...' or 'good'."}
  ,{type:"match",pairs:[{trg:"verdrietig",src:"to be sad"},{trg:"de allergie",src:"the allergy"},{trg:"bang",src:"afraid / scared"},{trg:"de dokter",src:"the doctor"},{trg:"rusten",src:"to rest"},{trg:"de vis",src:"the fish"},{trg:"het varken",src:"the pig"},{trg:"de verkoudheid",src:"the cold (illness)"}]},{type:"match",pairs:[{trg:"luister!",src:"listen!"},{trg:"stop!",src:"stop!"}]}]},
  {id:"v2u8l8d",title:"Een Afspraak Maken",icon:"📅",xp:15,board:true,steps:[
        {type:"intro",title:"Een Afspraak Maken",desc:"You already know 'de afspraak' and 'de huisarts'. Now learn the action phrases: how to call and book, confirm, cancel, and reschedule appointments. These are essential for Dutch life and tested on NT2 A2.",goals:["Call to make an appointment","Confirm or cancel a booking","Reschedule to a new time","Use polite Dutch telephone phrases"]},
        {type:"teach",trg:"een afspraak maken",src:"to make an appointment",pos:"verb",gender:null,phonetic:"un AF-sprahk MAH-kun",note:"Maken = to make (regular). Maak, maakt, maken.\nEen afspraak maken = to make an appointment.\nIk wil een afspraak maken = I want to make an appointment.",example:"A: Ik wil een afspraak maken bij de huisarts.\nB: Wanneer komt het u uit?\nA: Morgen als het kan.\nB: Morgen om 10 uur?",exampleSrc:"A: I want to make an appointment with the GP.\nB: When suits you?\nA: Tomorrow if possible.\nB: Tomorrow at 10?",funFact:"Dutch 'maken' and English 'make' both come from Proto-Germanic. They have been near-identical for over a thousand years."},
        {type:"teach",trg:"bevestigen",src:"to confirm",pos:"verb",gender:null,phonetic:"buh-VES-tuh-gun",note:"Regular -en verb. Bevestig, bevestigt, bevestigen.\nIk bel om te bevestigen = I call to confirm.\nAlso means to attach or secure.",example:"A: Ik bel om mijn afspraak te bevestigen.\nB: Ja, dinsdag om 11 uur, klopt dat?\nA: Ja, dat klopt. Dank u.\nB: Tot dinsdag.",exampleSrc:"A: I'm calling to confirm my appointment.\nB: Yes, Tuesday at 11, is that right?\nA: Yes, that's right. Thank you.\nB: See you Tuesday.",funFact:"'Bevestigen' has two meanings: to confirm AND to attach/secure. The root 'vast' (firm, fixed) connects both ideas."},
        {type:"teach",trg:"afzeggen",src:"to cancel",pos:"verb",gender:null,phonetic:"AF-zeg-gun",note:"SEPARABLE verb: af + zeggen.\nIk zeg mijn afspraak af.\nThe prefix 'af' goes to the end of the main clause.\nLiterally 'to say off'.",example:"A: Ik moet mijn afspraak afzeggen.\nB: Geen probleem. Wilt u een nieuwe?\nA: Ja, graag, volgende week.\nB: Woensdag om 14 uur?",exampleSrc:"A: I have to cancel my appointment.\nB: No problem. Would you like a new one?\nA: Yes please, next week.\nB: Wednesday at 2pm?",funFact:"Dutch separable verbs split in main clauses: 'Ik zeg de afspraak AF.' The prefix travels to the end. This follows consistent Dutch word-order rules."},
        {type:"teach",trg:"verzetten",src:"to reschedule / move to another time",pos:"verb",gender:null,phonetic:"fur-ZET-tun",note:"Regular -en verb. Verzet, verzet, verzetten.\nLiterally 'to move/displace'.\nIk wil de afspraak verzetten = I want to reschedule.",example:"A: Kan ik de afspraak verzetten?\nB: Natuurlijk. Welke dag past beter?\nA: Donderdag ochtend, als het kan.\nB: Donderdag om 9 uur, oké?",exampleSrc:"A: Can I reschedule the appointment?\nB: Of course. Which day works better?\nA: Thursday morning if possible.\nB: Thursday at 9, okay?",funFact:"'Verzetten' also means to move an object or to resist. 'Het verzet' (the Resistance) uses the same root with the sense of pushing back."},
        {type:"teach",trg:"Ik wil een afspraak maken voor...",src:"I want to make an appointment for...",pos:"intj",gender:null,note:"Standard phone opening for appointments.\nComplete with: de tandarts / volgende week / enz.\nPoliter: 'Ik zou graag een afspraak willen maken.'",example:"A: Goedemorgen, ik wil een afspraak maken bij de huisarts.\nB: Zeker. Ochtend of middag?\nA: Ochtend, bij voorkeur.\nB: Maandag om 9 uur?",exampleSrc:"A: Good morning, I want to make an appointment at the GP.\nB: Certainly. Morning or afternoon?\nA: Morning, preferably.\nB: Monday at 9?",funFact:"The Netherlands is one of the most appointment-driven societies in Europe. Even visiting a friend often requires planning ahead. 'Even bellen' (just call ahead) is a Dutch social norm."},
        {type:"teach",trg:"Wanneer komt het u uit?",src:"When suits you? / When is convenient for you?",pos:"intj",gender:null,note:"Formal receptionist question. 'U' = polite form of jij.\nUitkomen = to suit / to work out (time-wise).\nReply: 'Dinsdag ochtend past mij goed.'",example:"A: Wanneer komt het u uit voor de afspraak?\nB: Dinsdag of donderdag.\nA: Dan geef ik u dinsdag om 11 uur.\nB: Uitstekend, dank u.",exampleSrc:"A: When does it suit you for the appointment?\nB: Tuesday or Thursday.\nA: Then I'll give you Tuesday at 11.\nB: Excellent, thank you.",funFact:"'Uitkomen' has several meanings: to suit, to come out, to work out. In a scheduling context it always means 'to be convenient for someone'."},
        {type:"tip",title:"Bellen voor een Afspraak",text:"Standard script for calling a Dutch doctor's office:\n\n1. Opening:\n'Goedemorgen, ik wil een afspraak maken bij de huisarts.'\n\n2. Give your name:\n'Mijn naam is [name].'\n\n3. Indicate urgency:\n'Het is niet spoedeisend.' (not urgent)\n'Het is wel urgent.' (it is urgent)\n\n4. Confirm details:\n'Dus dinsdag om 10 uur, klopt dat?'\n\nKey vocabulary:\nde praktijk = the practice / clinic\nde tandarts = the dentist\nde controle = the check-up\nHuisartsPost = out-of-hours GP clinic"},
        {type:"mc",q:"Which verb means 'to cancel' an appointment in Dutch?",opts:["afzeggen","maken","bevestigen","verzetten"],ans:"afzeggen",hint:"This separable verb literally means 'to say off'. The prefix goes to the end of the clause."},
        {type:"fb",opts:["maken","nemen","zeggen","gaan"],hint:"'Een afspraak ___ ' is the standard Dutch phrase for booking an appointment.",s:"Ik wil een afspraak {1} bij de tandarts.",a:"maken"},
        {type:"mc",q:"'Ik zeg mijn afspraak af.'. where is the separable prefix 'af'?",opts:["At the start: 'af' comes before 'zeg'","At the end of the main clause","Directly next to 'zeg': afzeg","It disappears in the present tense"],ans:"At the end of the main clause",hint:"Dutch separable prefixes travel rightward through the sentence to its very last slot."},
        {type:"match",pairs:[{trg:"een afspraak maken",src:"to make an appointment"},{trg:"afzeggen",src:"to cancel"},{trg:"verzetten",src:"to reschedule"},{trg:"bevestigen",src:"to confirm"},{trg:"Wanneer komt het u uit?",src:"When suits you?"}]},
        {type:"fb",opts:["verzetten","afzeggen","bevestigen","maken"],hint:"Moving it to a different time, not cancelling it.",s:"Kan ik de afspraak {1}? Woensdag past mij beter.",a:"verzetten"}
  ]},
  {id:"nlv2_u8l_jobs_animals_sports",title:"Beroepen, Sport & Hobby's",icon:"⚽",xp:20,board:true,steps:[
    {type:"intro",title:"Beroepen, Sport en Hobby's",desc:"Three essential everyday topics: service professions you encounter daily, popular Dutch sports, and creative hobbies. All vocabulary is NT2 A1-A2 core and appears on the NT2 exams.",goals:["Learn 2 service-sector professions","Learn 4 sports and hobbies (verbs)","Learn 2 ball sports (nouns)","Learn 'kiezen' (to choose)","Practice with production-mode quizzes"]},
    {type:"teach",trg:"de ober",src:"the waiter",pos:"noun",gender:"c",phonetic:"duh OH-bur",note:"De-word. Plural: obers.\nBoth male and female servers are called 'de ober' in Dutch.\nA more formal term is 'de kelner'.",example:"A: Excuseer, ober!\nB: Ja, kan ik u helpen?\nA: Ik wil graag de rekening.\nB: Natuurlijk, een moment.",exampleSrc:"A: Excuse me, waiter!\nB: Yes, can I help you?\nA: I would like the bill.\nB: Of course, one moment.",funFact:"Dutch borrowed 'ober' from German (Ober = head waiter). It has been standard Dutch since the 19th century."},
    {type:"teach",trg:"de winkelier",src:"the shopkeeper",pos:"noun",gender:"c",phonetic:"duh WIN-kuh-leer",note:"De-word. Formed from 'winkel' (shop) + '-ier' suffix.\nThe -ier suffix creates a person noun: baker, seller.\nDe winkel = the shop. De winkelier = the person who runs it.",example:"A: De winkelier opent elke dag om negen uur.\nB: Ook op zaterdag?\nA: Ja, maar niet op zondag.\nB: Goed om te weten.",exampleSrc:"A: The shopkeeper opens every day at nine o'clock.\nB: On Saturday too?\nA: Yes, but not on Sunday.\nB: Good to know.",funFact:"Dutch uses the suffix '-ier' to make person nouns from places or activities: winkel (shop) + -ier = winkelier. The same suffix appears in 'portier' (doorman) and 'kasseier' (cashier)."},
    {type:"teach",trg:"het voetbal",src:"football / soccer",pos:"noun",gender:"n",phonetic:"hut FOOT-bal",note:"Het-word. Literally 'foot-ball'.\nVoetbal is the most popular sport in the Netherlands.\nVolleybal, basketbal, and handbal follow the same pattern.",example:"A: Kijk je graag naar voetbal?\nB: Ja, elk weekend!\nA: Ik ook. Voetbal is leuk!\nB: Ja, heel leuk.",exampleSrc:"A: Do you like watching football?\nB: Yes, every weekend!\nA: Me too. Football is fun!\nB: Yes, very fun.",funFact:"The Netherlands has been runners-up in the FIFA World Cup three times (1974, 1978, 2010). Ajax is the most internationally famous Dutch club."},
    {type:"teach",trg:"het tennis",src:"tennis",pos:"noun",gender:"n",phonetic:"hut TEN-nis",note:"Het-word. Plural not used (uncountable sport noun).\nTennis spelen = to play tennis.\nA popular summer sport in the Netherlands.",example:"A: Speel je tennis?\nB: Ja, elke zaterdag ochtend.\nA: Ik wil graag leren tennissen!\nB: Ja, graag! Ik ook.",exampleSrc:"A: Do you play tennis?\nB: Yes, every Saturday morning.\nA: I would like to learn to play tennis!\nB: Yes, please! Me too.",funFact:"The Netherlands hosts the Rotterdam Open (ATP) each year. Richard Krajicek, the 1996 Wimbledon champion, is Dutch."},
    {type:"teach",trg:"dansen",src:"to dance",pos:"verb",gender:null,phonetic:"DAN-sun",note:"Regular verb. Stem: dans.\nIk dans, jij danst, hij/zij danst, wij dansen.\nDans = also the noun: de dans (the dance).",example:"A: Dans je graag?\nB: Ja, ik dans elke week.\nA: Dat is leuk!\nB: Ja, ik vind het geweldig.",exampleSrc:"A: Do you like dancing?\nB: Yes, I dance every week.\nA: That is fun!\nB: Yes, I find it great.",funFact:"Germanic cousin of French 'danser', from which English 'dance' also comes. The Dutch word arrived via French in the Middle Ages."},
    {type:"teach",trg:"zingen",src:"to sing",pos:"verb",gender:null,phonetic:"ZING-un",note:"Irregular verb. Stem: zing.\nPast tense: zong. Past participle: gezongen.\nSame pattern as English: sing, sang, sung.",example:"A: Zing je in een koor?\nB: Ja, we zingen elke donderdag.\nA: Dat klinkt leuk!\nB: Je kunt mee komen.",exampleSrc:"A: Do you sing in a choir?\nB: Yes, we sing every Thursday.\nA: That sounds fun!\nB: You can come along.",funFact:"Germanic cousin of English 'sing', German 'singen'. All three languages show the same strong verb pattern (sing/sang/sung) inherited from Proto-Germanic."},
    {type:"teach",trg:"schilderen",src:"to paint",pos:"verb",gender:null,phonetic:"SKHIL-duh-run",note:"Regular verb. Stem: schilder.\nIk schilder, jij schildert, hij schildert.\nDe schilder = the painter (person or wall painter).",example:"A: Schilder je graag?\nB: Ja, altijd in het weekend.\nA: Wat schilder je?\nB: Landschappen en bloemen.",exampleSrc:"A: Do you like painting?\nB: Yes, always on the weekend.\nA: What do you paint?\nB: Landscapes and flowers.",funFact:"The Netherlands produced some of the world's greatest painters: Rembrandt, Vermeer, and Van Gogh. The 17th century Dutch Golden Age is called 'de Gouden Eeuw'."},
    {type:"teach",trg:"schaatsen",src:"to skate / ice skating",pos:"verb",gender:null,phonetic:"SKHAAT-sun",note:"Regular verb. Stem: schaats.\nAlso a noun: de schaats (the skate), de schaatsen (the skates).\nNatural ice skating is a beloved Dutch winter tradition.",example:"A: Kun je schaatsen?\nB: Ja, ik schaats altijd in de winter.\nA: Op ijs of op de schaatsbaan?\nB: Soms op het meer, als het kan.",exampleSrc:"A: Can you skate?\nB: Yes, I always skate in winter.\nA: On natural ice or at the rink?\nB: Sometimes on the lake, when it's possible.",funFact:"The Elfstedentocht (Eleven Cities Tour) is a legendary Dutch skating race on natural canals. It has only been held 15 times since 1909 because the ice must be at least 15cm thick."},
    {type:"teach",trg:"kiezen",src:"to choose",pos:"verb",gender:null,phonetic:"KEE-zun",note:"Irregular verb. Stem: kies.\nPast tense: koos. Past participle: gekozen.\nDe keuze = the choice (the noun form).",example:"A: Kies je voetbal of tennis?\nB: Ik kies voetbal. En jij?\nA: Ik kies zingen en schilderen!\nB: Dat is ook mooi.",exampleSrc:"A: Do you choose football or tennis?\nB: I choose football. And you?\nA: I choose singing and painting!\nB: That is also beautiful.",funFact:"Germanic cousin of German 'kiesen' (archaic) and related to English 'choose'. The past participle 'gekozen' shows the same vowel shift as English chosen."},
    {type:"tip",title:"Dutch Hobbies: Verb vs. Noun",text:"Dutch uses two patterns to talk about sports and hobbies:\n\nPattern 1: verb + graag = to like doing\nIk dans graag. = I like dancing.\nHij zingt graag. = He likes singing.\nZij schildert graag. = She likes painting.\n\nPattern 2: noun + spelen / doen = to play (a sport)\nIk speel voetbal. = I play football.\nZij speelt tennis. = She plays tennis.\n\nSome sports are also verbs:\nschaatsen = to skate (verb)\nfietsen = to cycle (verb)\nzwemmen = to swim (verb)\n\nNote: 'sporten' (to exercise) is a general verb that covers all physical activity."},
    {type:"mc",q:"Which Dutch word means 'to sing'?",opts:["zingen","schilderen","dansen","schaatsen"],ans:"zingen",hint:"Cognate with English: same meaning, same Germanic root."},
    {type:"fb",opts:["ober","winkelier","dokter","leraar"],hint:"The person who serves you food and drinks in a restaurant.",s:"Excuseer, ___! Ik wil graag de rekening.",a:"ober"},
    {type:"mc",q:"'Het voetbal' is the Dutch word for:",opts:["volleyball","football / soccer","handball","basketball"],ans:"football / soccer",hint:"The most popular sport in the Netherlands. Literally 'foot-ball'."},
    {type:"fb",opts:["dansen","zingen","schilderen","schaatsen"],hint:"Moving gracefully on ice in winter. A beloved Dutch tradition.",s:"Ik ___ altijd in de winter.\n(I always skate in winter.)",a:"schaatsen"},
    {type:"mc",q:"'De winkelier' is formed from:",opts:["wink + -el + -ier = wink seller","winkel + -aar = seller","winkel + -ier = shopkeeper","winkelen + -er = shopper"],ans:"winkel + -ier = shopkeeper",hint:"Find the root noun (shop in Dutch) plus the Dutch person-making suffix."},
    {type:"fb",opts:["kies","schilder","help","probeer"],hint:"Making a deliberate selection from two options.",s:"Ik ___ altijd voetbal. Tennis is ook leuk.",a:"kies"},
    {type:"match",pairs:[{trg:"dansen",src:"to dance"},{trg:"zingen",src:"to sing"},{trg:"schilderen",src:"to paint"},{trg:"schaatsen",src:"to skate"}]},
    {type:"fb",opts:["zingt","danst","schildert","schaatst"],hint:"She sings (third person singular, regular conjugation of 'zingen').",s:"Zij ___ graag in een koor.\n(She likes singing in a choir.)",a:"zingt"},
    {type:"mc",q:"Which sentence correctly says 'She plays tennis'?",opts:["Zij tennist graag.","Zij maakt tennis.","Zij doet tennis.","Zij speelt tennis."],ans:"Zij speelt tennis.",hint:"Sports played with a ball or racket take 'spelen' in Dutch."},
    {type:"drag_fill",hint:"The shopkeeper always opens on Saturday. I choose to go there.",s:"De {1} opent altijd op zaterdag. Ik {2} om daar naartoe te gaan.",blanks:{"1":"winkelier","2":"kies"},pool:["winkelier","kies","ober","zingt"]},
    {type:"match",pairs:[{trg:"het voetbal",src:"football / soccer"},{trg:"het tennis",src:"tennis"},{trg:"de ober",src:"the waiter"},{trg:"de winkelier",src:"the shopkeeper"},{trg:"kiezen",src:"to choose"}]}
  ]}
]};
